let state = {

  currentProjectId: null,

  editingRoomId: null,

  selMat: { floor: 'none', wall: 'none', ceilMats: [], wallZ1: 'none', wallZ2: 'none' },

  wallZoneMode: false,

  originalRoomData: null,

  elecPhotos: [],

};

