// =============================================

function renderProjectList() {
  const allProjects = DB.all();
  const list = document.getElementById('project-list');
  const badge = document.getElementById('header-project-count');
  
  if (badge) {
    badge.textContent = `${allProjects.length} dự án`;
  }

  if (allProjects.length === 0) {
    list.innerHTML = `<p style="padding:20px;text-align:center;color:var(--text-muted);font-size:12px;">Chưa có dự án nào</p>`;
    return;
  }

  // 1. Lấy thông tin tìm kiếm và sắp xếp từ UI
  const searchInput = document.getElementById('sidebar-project-search');
  const query = searchInput ? searchInput.value.toLowerCase().trim() : '';

  const sortSelect = document.getElementById('sidebar-project-sort');
  const sortMode = sortSelect ? sortSelect.value : 'newest';

  // 2. Lọc danh sách dự án
  let filtered = allProjects.filter(p => {
    const matchQuery = !query || 
      p.name.toLowerCase().includes(query) || 
      (p.client && p.client.toLowerCase().includes(query));
    return matchQuery;
  });

  // 3. Sắp xếp danh sách dự án
  filtered.sort((a, b) => {
    if (sortMode === 'az') return a.name.localeCompare(b.name, 'vi');
    if (sortMode === 'za') return b.name.localeCompare(a.name, 'vi');
    // newest: mặc định theo ngày tạo mới nhất
    const timeA = a.date ? new Date(a.date).getTime() : 0;
    const timeB = b.date ? new Date(b.date).getTime() : 0;
    return timeB - timeA;
  });

  // 4. Render danh sách dự án
  list.innerHTML = filtered.map(p => {
    const s = CALC.project(p);
    const active = p.id === state.currentProjectId;
    const folderIconSvg = `
      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="project-folder-icon">
        <path d="M4 20h16a2 2 0 0 0 2-2V8a2 2 0 0 0-2-2h-7.93a2 2 0 0 1-1.66-.9l-.82-1.2A2 2 0 0 0 7.93 3H4a2 2 0 0 0-2 2v13a2 2 0 0 0 2 2z"></path>
      </svg>
    `;

    return `
      <div class="project-item ${active ? 'active' : ''}" data-id="${p.id}" onclick="openProject('${p.id}')">
        <div class="project-item-title-row">
          ${folderIconSvg}
          <span class="project-item-name" title="${p.name}">${p.name}</span>
        </div>
        <div class="project-item-client">KH: ${p.client || 'Chưa nhập'}</div>
        <div class="project-item-footer">
          <span class="project-item-date">${p.date || ''}</span>
          <span class="project-item-rooms-badge">${s.rooms} phòng</span>
        </div>
      </div>
    `;
  }).join('');
}

function updateDashboardStats() {
  const allProjects = DB.all();
  let totalRooms = 0;
  let totalArea = 0;
  
  allProjects.forEach(p => {
    const s = CALC.project(p);
    totalRooms += s.rooms;
    totalArea += s.floor;
  });

  const sumProjectsVal = document.getElementById('sum-projects-val');
  const sumRoomsVal = document.getElementById('sum-rooms-val');
  const sumAreaVal = document.getElementById('sum-area-val');
  const sumExportsVal = document.getElementById('sum-exports-val');
  const mainProjectSubtitle = document.getElementById('main-project-subtitle');

  if (sumProjectsVal) sumProjectsVal.textContent = allProjects.length;
  if (sumRoomsVal) sumRoomsVal.textContent = totalRooms;
  if (sumAreaVal) sumAreaVal.textContent = totalArea.toFixed(1);
  if (sumExportsVal) {
    sumExportsVal.textContent = localStorage.getItem('bkl_export_count') || '0';
  }
  if (mainProjectSubtitle) {
    mainProjectSubtitle.textContent = `${allProjects.length} dự án đang thực hiện`;
  }
}

function renderDashboardProjects() {
  console.log('DEBUG: renderDashboardProjects started');
  updateDashboardStats();
  console.log('DEBUG: updateDashboardStats finished');
  
  const grid = document.getElementById('project-cards-grid');
  if (!grid) {
    console.log('DEBUG: project-cards-grid element not found');
    return;
  }
  
  const allProjects = DB.all();
  console.log('DEBUG: renderDashboardProjects loaded projects count:', allProjects.length);
  if (allProjects.length === 0) {
    grid.innerHTML = `
      <div style="grid-column: 1/-1; text-align: center; padding: 52px 20px; color: var(--text-muted);">
        <div style="font-size: 48px; margin-bottom: 12px;">📁</div>
        <p style="font-size: 14px;">Chưa có dự án nào. Bấm <strong>Tạo mới</strong> để bắt đầu.</p>
      </div>
    `;
    return;
  }

  const searchInput = document.getElementById('project-search-input');
  const query = searchInput ? searchInput.value.toLowerCase().trim() : '';

  const activeTab = document.querySelector('#project-filter-tabs .filter-tab.active');
  const filterType = activeTab ? activeTab.dataset.type : 'all';

  let filtered = allProjects.filter(p => {
    const matchQuery = !query || p.name.toLowerCase().includes(query) || (p.client && p.client.toLowerCase().includes(query));
    if (!matchQuery) return false;

    if (filterType === 'all' || filterType === 'in_progress') return true;
    if (filterType === 'residential') return p.type === 'residential';
    if (filterType === 'hotel') return p.type === 'hotel' || p.type === 'resort';
    if (filterType === 'y_te') return p.type === 'hospital' || p.type === 'clinic';
    if (filterType === 'office') return p.type === 'office';
    if (filterType === 'spa') return p.type === 'spa';
    
    return true;
  });

  const sortMode = window._dashboardSort || 'newest';
  filtered.sort((a, b) => {
    if (sortMode === 'newest') return (b.createdAt || 0) - (a.createdAt || 0);
    if (sortMode === 'oldest') return (a.createdAt || 0) - (b.createdAt || 0);
    if (sortMode === 'az') return a.name.localeCompare(b.name, 'vi');
    if (sortMode === 'rooms') {
      const roomsA = a.rooms ? a.rooms.length : 0;
      const roomsB = b.rooms ? b.rooms.length : 0;
      return roomsB - roomsA;
    }
    return 0;
  });

  console.log('DEBUG: renderDashboardProjects rendering', filtered.length, 'filtered projects');
  grid.innerHTML = filtered.map(p => {
    const s = CALC.project(p);
    const cost = CALC.projectCost(p);
    
    let typeLabel = 'Khác';
    let badgeClass = 'badge-secondary';
    if (p.type === 'residential') { typeLabel = 'Nhà ở'; badgeClass = 'badge-primary'; }
    else if (p.type === 'hotel' || p.type === 'resort') { typeLabel = 'Kh sạn'; badgeClass = 'badge-warning'; }
    else if (p.type === 'hospital' || p.type === 'clinic') { typeLabel = 'Y tế'; badgeClass = 'badge-success'; }
    else if (p.type === 'office') { typeLabel = 'Văn phòng'; badgeClass = 'badge-info'; }
    else if (p.type === 'spa') { typeLabel = 'Spa'; badgeClass = 'badge-danger'; }

    const dateObj = p.createdAt ? new Date(p.createdAt) : new Date();
    const formattedTime = `${dateObj.getDate()}/${dateObj.getMonth() + 1}/${dateObj.getFullYear()}`;

    const progress = p.rooms && p.rooms.length > 0 ? Math.min(100, 30 + p.rooms.length * 15) : 15;
    const progressColor = progress === 100 ? '#2D6A4F' : 'var(--brand-gold)';

    return `
      <div class="project-card" data-id="${p.id}">
        <div class="card-header">
          <div class="project-title-row">
            <div class="project-name">${p.name}</div>
            <span class="badge ${badgeClass}">${typeLabel}</span>
          </div>
          <span class="updated-time">Cập nhật: ${formattedTime}</span>
        </div>
        <div class="card-body">
          <div class="stat-col">
            <span class="stat-num">${s.rooms}</span>
            <span class="stat-lbl">Phòng</span>
          </div>
          <div class="stat-col">
            <span class="stat-num">${s.floor.toFixed(1)}</span>
            <span class="stat-lbl">m² sàn</span>
          </div>
          <div class="stat-col">
            <span class="stat-num" style="color:var(--brand-gold);">${fmt(cost, 0)} đ</span>
            <span class="stat-lbl">Chi phí</span>
          </div>
        </div>
        <div class="card-footer">
          <div class="progress-container">
            <span class="progress-lbl">Tiến độ</span>
            <div class="progress-track">
              <div class="progress-bar" style="width: ${progress}%; background-color: ${progressColor};"></div>
            </div>
            <span class="progress-pct">${progress}%</span>
          </div>
          <i data-lucide="chevron-right" class="arrow-icon" style="width: 16px; height: 16px;"></i>
        </div>
      </div>
    `;
  }).join('');

  console.log('DEBUG: renderDashboardProjects created innerHTML');
  if (window.lucide) {
    window.lucide.createIcons();
    console.log('DEBUG: renderDashboardProjects lucide icons created');
  }

  grid.querySelectorAll('.project-card').forEach(card => {
    card.addEventListener('click', () => {
      openProject(card.dataset.id);
    });

    card.addEventListener('contextmenu', (e) => {
      e.preventDefault();
      showContextMenu(card.dataset.id, e.clientX, e.clientY);
    });
  });
  console.log('DEBUG: renderDashboardProjects fully finished');
}

function showContextMenu(id, x, y) {
  const project = DB.get(id);
  if (!project) return;

  const overlay = document.getElementById('context-menu-overlay');
  if (!overlay) return;

  const card = overlay.querySelector('.context-menu-card');
  const nameEl = document.getElementById('context-menu-project-name');

  if (nameEl) nameEl.textContent = project.name;
  overlay.style.display = 'block';

  const cardWidth = 200;
  const cardHeight = 180;
  const screenWidth = window.innerWidth;
  const screenHeight = window.innerHeight;

  let posX = x;
  let posY = y;

  if (x + cardWidth > screenWidth) posX = screenWidth - cardWidth - 10;
  if (y + cardHeight > screenHeight) posY = screenHeight - cardHeight - 10;

  if (card) {
    card.style.position = 'fixed';
    card.style.left = `${posX}px`;
    card.style.top = `${posY}px`;
  }

  document.getElementById('btn-ctx-open').onclick = () => {
    openProject(id);
    overlay.style.display = 'none';
  };

  document.getElementById('btn-ctx-edit').onclick = () => {
    overlay.style.display = 'none';
    openProjectModal(project);
  };

  document.getElementById('btn-ctx-delete').onclick = () => {
    overlay.style.display = 'none';
    if (confirm(`Xóa dự án "${project.name}"?\n\nHành động này không thể hoàn tác.`)) {
      DB.remove(id);
      if (state.currentProjectId === id) {
        state.currentProjectId = null;
        const ws = document.getElementById('project-workspace');
        if (ws) {
          ws.style.display = 'none';
          ws.classList.remove('visible');
        }
      }
      renderProjectList();
      renderDashboardProjects();
    }
  };

  document.getElementById('btn-ctx-close').onclick = () => {
    overlay.style.display = 'none';
  };

  overlay.onclick = (e) => {
    if (e.target === overlay) overlay.style.display = 'none';
  };
}

// =============================================

// 7. MỞ DỰ ÁN

// =============================================

function openProject(id) {
  console.log('DEBUG: openProject started for id:', id);

  const project = DB.get(id);

  if (!project) {
    console.log('DEBUG: openProject project not found in DB');
    return;
  }

  state.currentProjectId = id;

  // Hủy active view 1 (dashboard), active view 2 (workspace)
  document.getElementById('view-projects')?.classList.remove('active');
  document.getElementById('view-workspace')?.classList.add('active');

  // Active bottom nav tab tương ứng (tab bốc KL)
  document.querySelectorAll('.bottom-nav .nav-tab').forEach(t => t.classList.remove('active'));
  document.querySelector('.bottom-nav .nav-tab[data-tab="estimate"]')?.classList.add('active');

  document.getElementById('empty-state').style.display = 'none';

  const ws = document.getElementById('project-workspace');

  ws.style.display = 'block';

  ws.classList.add('visible');

  // Điền thông tin

  document.getElementById('ws-project-name').textContent = project.name;

  document.getElementById('ws-project-client').textContent  = project.client  ? `👤 ${project.client}`  : '';

  document.getElementById('ws-project-address').textContent = project.address ? `📍 ${project.address}` : '';

  document.getElementById('ws-project-date').textContent    = project.date    ? `📅 ${project.date}`    : '';

  console.log('DEBUG: openProject calling renderProjectList');
  renderProjectList();

  console.log('DEBUG: openProject calling refreshWorkspace');
  refreshWorkspace();
  console.log('DEBUG: openProject finished');

}

function refreshWorkspace() {

  const project = DB.get(state.currentProjectId);

  if (!project) return;

  renderStats(project);

  renderRooms(project);

  renderBOQ(project);

}

// =============================================

// 8. RENDER STATS

// =============================================

function renderStats(project) {

  const s = CALC.project(project);

  document.getElementById('stat-rooms').textContent      = s.rooms;

  document.getElementById('stat-items').textContent      = s.items;

  document.getElementById('stat-floor-area').textContent = fmt(s.floor);

  document.getElementById('stat-wall-area').textContent  = fmt(s.wall);

}

// =============================================

// 9. RENDER DANH SÁCH PHÒNG

// =============================================

function renderRooms(project) {

  const grid = document.getElementById('rooms-grid');

  if (!project.rooms || project.rooms.length === 0) {

    grid.innerHTML = `

      <div style="grid-column:1/-1;text-align:center;padding:52px 20px;color:var(--text-muted);">

        <div style="font-size:44px;margin-bottom:14px;">🏠</div>

        <p style="font-size:14px;">Chưa có phòng nào. Bấm <strong>+ Thêm Phòng</strong> để bắt đầu.</p>

      </div>`;

    return;

  }

  grid.innerHTML = project.rooms.map(room => {

    const calc  = CALC.room(room);

    const fMat  = getMat('floor',   room.floorMat);

    const wMat  = getMat('wall',    room.wallMat);

    const ceilMatId = Array.isArray(room.ceilMats) && room.ceilMats.length ? room.ceilMats[0] : (room.ceilMat || 'none');

    const cMat  = getMat('ceiling', ceilMatId);

    // Hiển thị kích thước gốc theo mm (format vi-VN)

    const dimLabel = `${fmtMM(room.D||0)} × ${fmtMM(room.R||0)} × cao ${fmtMM(room.H||0)} mm`;

    const badges = [

      fMat.id !== 'none' ? `<span class="mat-badge floor">Sàn: ${fMat.label}</span>` : '',

      wMat.id !== 'none' ? `<span class="mat-badge wall">Tường: ${wMat.label}</span>` : '',

      cMat.id !== 'none' ? `<span class="mat-badge ceiling">Trần: ${cMat.label}</span>` : '',

    ].filter(Boolean).join('');

    return `

      <div class="room-card">

        <div class="room-card-header">

          <div>

            <div class="room-card-name">${room.name}</div>

            <div class="room-card-dim">${dimLabel}</div>

          </div>

          <div class="room-card-actions">

            <button class="btn-icon-xs" onclick="editRoom('${room.id}')" title="Sửa phòng">

              <i data-lucide="edit-2"></i>

            </button>

            <button class="btn-icon-xs danger" onclick="deleteRoom('${room.id}')" title="Xóa phòng">

              <i data-lucide="trash-2"></i>

            </button>

          </div>

        </div>

        <div class="room-materials">

          ${badges || '<span style="color:var(--text-muted);font-size:11px;">Chưa chọn vật liệu</span>'}

        </div>

        <div class="room-quick-stats">

          <div class="rqs-item">

            <span class="rqs-val">${fmt(calc.rawFloor)}</span>

            <span class="rqs-lbl">m² sàn</span>

          </div>

          <div class="rqs-item">

            <span class="rqs-val">${fmt(calc.rawWall)}</span>

            <span class="rqs-lbl">m² tường</span>

          </div>

          <div class="rqs-item">

            <span class="rqs-val">${(2*((+room.D||0)/1000 + (+room.R||0)/1000)).toFixed(2).replace('.',',')}</span>

            <span class="rqs-lbl">m chu vi</span>

          </div>

          <div class="rqs-item">

            <span class="rqs-val">${calc.items.length}</span>

            <span class="rqs-lbl">hạng mục</span>

          </div>

        </div>

        <div class="room-card-photos" style="margin-top: 12px; padding-top: 10px; border-top: 1px dashed var(--border-color); display: flex; align-items: center; justify-content: space-between; font-size: 12px;">

          <span style="color: var(--text-secondary);">📷 Ảnh hiện trạng: <strong style="color: var(--brand-blue-light);">${getRoomPhotosCount(room)}</strong> tấm</span>

          <div>

            <input type="file" accept="image/*" multiple id="room-card-file-${room.id}" style="display: none;" onchange="handleRoomCardPhotoSelect(event, '${room.id}')">

            <button class="btn-primary" style="padding: 2px 8px; font-size: 11px; height: auto;" onclick="document.getElementById('room-card-file-${room.id}').click()">+ Thêm ảnh</button>

          </div>

        </div>

      </div>`;

  }).join('');

  reIcons();

}

// =============================================

// 10. RENDER BẢNG DỰ TOÁN

// =============================================

function renderBOQ(project) {

  const tbody = document.getElementById('boq-tbody');

  const summaryTbody = document.getElementById('boq-summary-tbody');

  // Populate the room filter dropdown

  const filterSelect = document.getElementById('boq-room-filter');

  if (filterSelect) {

    const prevVal = filterSelect.value || 'all';

    let filterHtml = '<option value="all">File tổng</option>';

    (project.rooms || []).forEach(r => {

      filterHtml += `<option value="${r.id}">${r.name}</option>`;

    });

    filterSelect.innerHTML = filterHtml;

    // Restore value if it still exists in the options

    if (Array.from(filterSelect.options).some(opt => opt.value === prevVal)) {

      filterSelect.value = prevVal;

    } else {

      filterSelect.value = 'all';

    }

  }

  if (!project.rooms || project.rooms.length === 0) {

    if (tbody) tbody.innerHTML = `

      <tr><td colspan="10" style="text-align:center;padding:36px;color:var(--text-muted);">Chưa có dữ liệu. Hãy thêm phòng trước.</td></tr>`;

    if (summaryTbody) summaryTbody.innerHTML = `

      <tr><td colspan="7" style="text-align:center;padding:20px;color:var(--text-muted);">Chưa có dữ liệu. Hãy thêm phòng trước.</td></tr>`;

    return;

  }

  // --- Render Bảng Tổng Hợp (có cột riêng cho từng phòng) ---

  const summaryItems = CALC.projectSummary(project);

  const rooms = project.rooms || [];

  // Cập nhật header bảng tổng hợp động theo số phòng

  const sumTable = summaryTbody ? summaryTbody.closest('table') : null;

  if (sumTable) {

    const existThead = sumTable.querySelector('thead');

    if (existThead) {

      const roomCols = rooms.map(r => `<th style="width:90px;text-align:right;color:var(--brand-blue-light);font-size:11px;">${r.name.length > 12 ? r.name.substring(0,12)+'…' : r.name}</th>`).join('');

      existThead.innerHTML = `<tr>

        <th style="width:40px;text-align:center;">STT</th>

        <th>Hạng Mục</th>

        <th style="width:58px;text-align:center;">Đ.Vị</th>

        ${roomCols}

        <th style="width:100px;text-align:right;">Tổng SL</th>

        <th style="width:110px;text-align:right;">Đơn Giá</th>

        <th style="width:120px;text-align:right;">Thành Tiền</th>

      </tr>`;

    }

  }

  if (summaryTbody) {

    const totalCols = 4 + rooms.length; // STT + Hạng mục + ĐV + phòng... + Tổng + ĐG + TT = rooms.length+5

    if (summaryItems.length === 0) {

    summaryTbody.innerHTML = `<tr><td colspan="${totalCols + 2}" style="text-align:center;padding:20px;color:var(--text-muted);">Chưa có dữ liệu tổng hợp. Hãy chọn vật liệu hoặc thêm thiết bị cho phòng.</td></tr>`;

  } else {

    let sumHtml = '';

    const groups = { construction: [], furniture: [], elec: [], sanitary: [] };

    summaryItems.forEach(item => {

      groups[categorizeSummaryItem(item)].push(item);

    });

    const catRomNums = ['I', 'II', 'III', 'IV', 'V', 'VI'];

    let catRomIdx = 0;

    const categoriesConfig = [
      { key: 'construction', rom: 'I',   label: 'XÂY DỰNG CƠ BẢN (bao gồm tất cả các hạng mục sàn tường trần)' },
      { key: 'elec',         rom: 'II',  label: 'THIẾT BỊ ĐIỆN' },
      { key: 'furniture',    rom: 'III', label: 'THIẾT BỊ NỘI THẤT' },
      { key: 'sanitary',     rom: 'IV',  label: 'NHÀ VỆ SINH: THIẾT BỊ VỆ SINH VÀ CHỐNG THẤM' }
    ];

    categoriesConfig.forEach(catConf => {

      const itemsInCat = groups[catConf.key];

      if (itemsInCat && itemsInCat.length > 0) {

        const rom = catConf.rom;

        sumHtml += `<tr class="boq-room-header" style="background:rgba(255,255,255,0.05);"><td style="text-align:center;font-weight:700;color:var(--brand-blue-light);">${rom}</td><td colspan="${3 + rooms.length + 2}" style="font-weight:700;color:var(--text-main);">${catConf.label.toUpperCase()}</td></tr>`;

        let itemStt = 1;

        itemsInCat.forEach(item => {

          const roomQtyCols = rooms.map(r => {

            const calc = CALC.room(r);

            const match = calc.items.find(it => it.label === item.label && it.unit === item.unit);

            const q = match ? match.qty : 0;

            return `<td style="text-align:right;font-size:12px;color:var(--text-secondary);">${q > 0 ? fmt(q) : '—'}</td>`;

          }).join('');

          sumHtml += `

            <tr>

              <td style="text-align:center;color:var(--text-muted);font-size:12px;">${itemStt++}</td>

              <td style="font-weight:600;color:var(--text-main);">${item.label}</td>

              <td style="text-align:center;font-size:12px;color:var(--text-secondary);">${item.unit}</td>

              ${roomQtyCols}

              <td style="text-align:right;font-weight:700;color:var(--brand-blue-light);">${fmt(item.qty)}</td>

              <td style="text-align:right;color:var(--text-secondary);">${item.price ? fmt(item.price, 0) : '—'}</td>

              <td style="text-align:right;font-weight:700;color:var(--text-main);">${item.total ? fmt(item.total, 0) : '—'}</td>

            </tr>

          `;

        });

      }

    });

    // ── Chi Phí Khác (cấp dự án) ──────────────────────────

    const oc = project.otherCosts || {};

    const totalFloorSum = rooms.reduce((s, r) => s + (+r.D||0)/1000 * (+r.R||0)/1000, 0);

    const OC_SUM = [

      { key:'transport',   label:'Phí vận chuyển',   unit:'gói', autoQty:false, defaultQty:1 },

      { key:'debris',      label:'Phí tháo gỡ trần, vận chuyển + đổ xà bần, bao rác',      unit:'m²',     autoQty:true  },

      { key:'scaffold',    label:'Phí thuê giàn giáo',                                       unit:'m²',     autoQty:true  },

      { key:'design',      label:'Phí thiết kế',                                             unit:'m²',     autoQty:true  },

      { key:'supervision', label:'Phí giám sát ngoại tỉnh',                                  unit:'lần',    autoQty:false, defaultQty:1 },

    ];

    const blankRoomCols = rooms.map(() => `<td style="text-align:right;color:var(--text-muted);">—</td>`).join('');

    let hasOcRow = false;

    let ocSttSum = 1;

    OC_SUM.forEach(tmpl => {

      const saved = oc[tmpl.key] || {};

      const qty   = tmpl.autoQty ? +totalFloorSum.toFixed(2) : +(saved.qty != null ? saved.qty : tmpl.defaultQty);

      const price = +(saved.price || 0);

      const total = qty * price;

      if (qty > 0 || price > 0) {

        if (!hasOcRow) {

          const rom = catRomNums[catRomIdx++];

          sumHtml += `<tr class="boq-other-header" style="background:rgba(255,160,0,0.08);"><td style="text-align:center;font-weight:700;color:var(--brand-gold);">${rom}</td><td colspan="${3 + rooms.length + 2}" style="font-weight:700;color:var(--brand-gold);">${'CHI PHÍ KHÁC'}</td></tr>`;

          hasOcRow = true;

        }

        sumHtml += `<tr style="border-bottom:1px solid rgba(255,255,255,0.05);">

          <td style="text-align:center;color:var(--text-muted);font-size:12px;">${ocSttSum++}</td>

          <td style="color:var(--text-main);">${tmpl.label}${tmpl.autoQty ? ' <span style="font-size:10px;color:var(--brand-blue-light);">tự động theo sàn</span>' : ''}</td>

          <td style="text-align:center;font-size:12px;color:var(--text-secondary);">${tmpl.unit}</td>

          ${blankRoomCols}

          <td style="text-align:right;color:var(--brand-blue-light);">${fmt(qty)}</td>

          <td style="text-align:right;color:var(--text-secondary);">${price ? fmt(price, 0) : '<em style="color:var(--text-muted);font-size:11px;">chưa nhập</em>'}</td>

          <td style="text-align:right;font-weight:700;color:var(--text-main);">${total ? fmt(total, 0) : '—'}</td>

        </tr>`;

      }

    });

    summaryTbody.innerHTML = sumHtml;

  }

  }

  let html = '';

  let stt = 1;

  const romanNums = ['I','II','III','IV','V','VI','VII','VIII','IX','X',

                     'XI','XII','XIII','XIV','XV','XVI','XVII','XVIII','XIX','XX'];

  project.rooms.forEach((room, idx) => {

    const calc = CALC.room(room);

    stt = 1;   // Reset STT moi phong

    const D = (+room.D || 0) / 1000;

    const R = (+room.R || 0) / 1000;

    const H = (+room.H || 0) / 1000;

    const perim = (2 * (D + R)).toFixed(2).replace('.',',');

    const roman = 'I';

    let subRomIdx = 1; // sub-section Roman counter (1-indexed, I=construction, II=elec)

    // Header: BẢNG KHỐI LƯỢNG - [ROOM NAME] làm tiêu đề phụ, và dòng I. XÂY DỰNG CƠ BẢN

    html += `

      <tr class="boq-room-title" data-kr="${room.id}" style="background:rgba(255,255,255,0.02);border-top:2px solid var(--border-color);"><td colspan="10" style="text-align:center;font-weight:800;font-size:14px;color:var(--brand-blue-light);padding:10px 0;">BẢNG KHỐI LƯỢNG - ${room.name.toUpperCase()}</td></tr>

      <tr class="boq-room-header" data-kr="${room.id}">

        <td colspan="10">${roman}. XÂY DỰNG CƠ BẢN — ${room.name.toUpperCase()}</td>

      </tr>`;

    if (calc.items.length === 0) {

      html += `<tr data-kr="${room.id}"><td colspan="10" style="color:var(--text-muted);font-style:italic;padding:6px 14px;font-size:12px;">Chưa chọn vật liệu</td></tr>`;

    } else {

      const allItems = calc.items;

      allItems.forEach((item, itemIdx) => {
        if (['woodworkNote', 'plumbingNote', 'waterproofNote'].includes(item.surface)) return;

        const key = item._key || item.surface;

        const isFirst = itemIdx === 0;

        const isLast  = itemIdx === allItems.length - 1;

        // --- Section headers (no move buttons) ---

        if (item.surface === 'elecHeader') {

          stt = 1; // Reset STT khi vào phần Điện

          html += `<tr class="boq-elec-header" data-key="${key}" data-kr="${room.id}"><td colspan="10">${romanNums[subRomIdx++] || subRomIdx}. THIẾT BỊ ĐIỆN</td></tr>`;

          return;

        }

        if (item.surface === 'noteHeader') {

          stt = 1; // Reset STT khi vào phần Ghi chú

          html += `<tr class="boq-note-header" data-key="${key}" data-kr="${room.id}"><td colspan="10">${romanNums[subRomIdx++] || subRomIdx}. CHI TIẾT TỪ GHI CHÚ</td></tr>`;

          return;

        }

        // --- Custom items (IN HOA = sub-header + reset STT) ---

        if (item.surface === 'custom') {

          const ci = (room.customItems||[]).find(c => c.id === item.itemId);

          if (!ci) return;

          const labelTrim = (ci.label||'').trim();

          const isSubHdr  = labelTrim.length > 1 && labelTrim === labelTrim.toUpperCase();

          if (isSubHdr) {

            stt = 1; // reset STT

            const subRom = romanNums[subRomIdx++] || subRomIdx;

            html += `

              <tr class="boq-sub-header" data-key="ci:${ci.id}" data-kr="${room.id}" data-ci="${ci.id}">

                <td></td>

                <td colspan="8" class="boq-sub-header-cell" style="font-weight:700;color:var(--brand-purple-light);">${subRom}. ${ci.label}

                  <span class="ci-action-group">

                    <button onclick="moveBoqRow('${room.id}','ci:${ci.id}',-1)" class="btn-ci-action boq-move-up" title="Lên" ${isFirst?'disabled':''}>&#8593;</button>

                    <button onclick="moveBoqRow('${room.id}','ci:${ci.id}',1)"  class="btn-ci-action boq-move-dn" title="Xuống" ${isLast?'disabled':''}>&#8595;</button>

                    <button onclick="startEditRow('${room.id}','${ci.id}')" class="btn-ci-action btn-edit-ci" title="Sửa">&#9998;</button>

                    <button onclick="removeCustomItem('${room.id}','${ci.id}')" class="btn-del-ci" title="Xóa">&#215;</button>

                  </span>

                </td>

                <td></td>

              </tr>`;

            return;

          }

          const qty = +ci.qty||0, price = +ci.price||0;

          html += `

            <tr class="boq-custom-item" data-key="ci:${ci.id}" data-kr="${room.id}" data-ci="${ci.id}">

              <td style="color:var(--text-muted);font-size:12px;text-align:center;">${stt++}</td>

              <td style="color:#a78bfa;font-weight:600;">${ci.label}</td>

              <td class="boq-dim"></td><td class="boq-dim"></td><td class="boq-dim"></td>

              <td style="color:var(--text-secondary);text-align:center;font-size:12px;">${ci.unit}</td>

              <td class="boq-qty">${fmt(qty, 2)}</td>

              <td class="boq-price">${price ? fmt(price, 0) : ''}</td>

              <td class="boq-total">${(qty * price) ? fmt(qty * price, 0) : ''}</td>

              <td class="boq-note" style="white-space:nowrap;">

                <span style="margin-right:4px;color:var(--text-muted);font-size:11px;">${ci.note || ''}</span>

                <span class="ci-action-group">

                  <button onclick="startEditRow('${room.id}','${ci.id}')" class="btn-ci-action btn-edit-ci" title="Sửa">&#9998;</button>

                  <button onclick="moveBoqRow('${room.id}','ci:${ci.id}',-1)" class="btn-ci-action boq-move-up" title="Lên" ${isFirst?'disabled':''}>&#8593;</button>

                  <button onclick="moveBoqRow('${room.id}','ci:${ci.id}',1)"  class="btn-ci-action boq-move-dn" title="Xuống" ${isLast?'disabled':''}>&#8595;</button>

                  <button onclick="removeCustomItem('${room.id}','${ci.id}')" class="btn-del-ci" title="Xóa">&#215;</button>

                </span>

              </td>

            </tr>`;

          return;

        }

        // --- Regular items ---

        const noStt     = false;

        const isManual  = item.surface === 'elecManual';

        const isNoteItem= item.surface === 'noteItem';

        const qtyDisplay = (isManual && item.qty === 0)

          ? `<span style="color:var(--brand-gold);font-style:italic;">-- tự điền</span>`

          : (isNoteItem && item.qty === 0)

            ? `<span style="color:var(--text-muted);font-style:italic;">--</span>`

          : (item.formula

              ? `<span data-formula="${item.formula.replace(/"/g,'&quot;')}" onclick="toggleFormula(this)" class="boq-qty has-formula" title="Click để xem công thức">${fmt(item.qty,2)}</span>`

              : fmt(item.qty, 2));

        html += `

          <tr class="${isManual?'boq-elec-manual':''} ${isNoteItem?'boq-note-item':''}" data-key="${key}" data-kr="${room.id}">

            <td style="color:var(--text-muted);font-size:12px;text-align:center;">${noStt?'':stt++}</td>

            <td${isManual?' style="color:var(--brand-gold);font-style:italic;"':''}${isNoteItem?' style="color:var(--text-secondary);font-style:italic;"':''}>${item.label}</td>

            <td class="boq-dim">${item.dai  ? fmtMM(item.dai)  : ''}</td>

            <td class="boq-dim">${item.rong ? fmtMM(item.rong) : ''}</td>

            <td class="boq-dim">${item.cao  ? fmtMM(item.cao)  : (item.hFull?fmtMM(item.hFull):'')}</td>

            <td style="color:var(--text-secondary);text-align:center;">${item.unit}</td>

            <td class="boq-qty">${qtyDisplay}</td>

            <td class="boq-price">${item.price ? fmt(item.price,0) : ''}</td>

            <td class="boq-total">${item.total ? fmt(item.total,0) : ''}</td>

            <td class="boq-note">
              <span class="boq-note-txt">
                ${(() => {
                  let noteHtml = item.note || '';
                  const catPhotos = getRoomPhotos(room, item.photoCategory);
                  if (catPhotos.length > 0) {
                    const photosMarkup = `<div class="boq-row-photos" style="display:flex; flex-wrap:wrap; gap:4px; margin-top:4px;">` +
                      catPhotos.map(p => `
                        <img src="${p.data}" style="width:120px; max-width:120px; height:auto; border-radius:4px; border:1px solid rgba(255,255,255,0.1); cursor:pointer;" onclick="window.viewPhotoData('${p.data.replace(/'/g, "\\'")}')" title="${p.name}">
                      `).join('') + `</div>`;
                    noteHtml = noteHtml ? `${noteHtml}<br>${photosMarkup}` : photosMarkup;
                  }
                  return noteHtml;
                })()}
              </span>

              <span class="ci-action-group">

                <button onclick="moveBoqRow('${room.id}','${key}',-1)" class="btn-ci-action boq-move-up" title="Lên" ${isFirst?'disabled':''}>&#8593;</button>

                <button onclick="moveBoqRow('${room.id}','${key}',1)"  class="btn-ci-action boq-move-dn" title="Xuống" ${isLast?'disabled':''}>&#8595;</button>

              </span>

            </td>

          </tr>`;

      });

      // Insert-bar + Them button at end

      html += `

        <tr class="boq-add-row" data-kr="${room.id}">

          <td colspan="10">

            <button class="btn-add-custom-item" onclick="startInsertRow('${room.id}', null)">

              &#10010; Thêm hạng mục thủ công

            </button>

          </td>

        </tr>`;

      // ── Per-room Chi Phí Khác (ẩn mặc định, hiện khi lọc theo phòng) ──

      const roomArea = +(D * R).toFixed(2);

      const ocPR = project.otherCosts || {};

      const OC_PR = [

        { key:'transport',   label:'Phí vận chuyển',   unit:'gói', autoQty:false, defaultQty:1 },

        { key:'debris',      label:'Phí tháo gỡ trần, vận chuyển + đổ xà bần, bao đựng rác',     unit:'m²',     autoQty:true },

        { key:'scaffold',    label:'Phí thuê giàn giáo',                                           unit:'m²',     autoQty:true },

        { key:'design',      label:'Phí thiết kế',                                                 unit:'m²',     autoQty:true },

        { key:'supervision', label:'Phí giám sát ngoại tỉnh',                                      unit:'lần',    autoQty:false, defaultQty:1 },

      ];

      html += `<tr class="boq-room-oc-hdr" data-kr="${room.id}" style="display:none;">

        <td colspan="10" style="padding:6px 12px;font-weight:700;color:var(--brand-gold);font-size:12px;background:rgba(255,160,0,0.08);">

          ${romanNums[subRomIdx++] || subRomIdx}. 💰 CHI PHÍ KHÁC — ${room.name}

        </td>

      </tr>`;

      let prStt = 1;

      OC_PR.forEach(tmpl => {

        const saved  = ocPR[tmpl.key] || {};

        const qty    = tmpl.autoQty ? roomArea : +(saved.qty != null ? saved.qty : tmpl.defaultQty);

        const price  = +(saved.price || 0);

        const total  = qty * price;

        html += `<tr class="boq-room-oc-item" data-kr="${room.id}" style="display:none;">

          <td style="text-align:center;color:var(--text-muted);font-size:12px;">${prStt++}</td>

          <td>${tmpl.label}${tmpl.autoQty ? ' <span class="oc-auto-tag">diện tích phòng này</span>' : ''}</td>

          <td class="boq-dim"></td><td class="boq-dim"></td><td class="boq-dim"></td>

          <td style="color:var(--text-secondary);text-align:center;">${tmpl.unit}</td>

          <td class="boq-qty">${fmt(qty, 2)}</td>

          <td class="boq-price">${price ? fmt(price, 0) : '<em style="color:var(--text-muted);font-size:11px;">chưa nhập</em>'}</td>

          <td class="boq-total">${total ? fmt(total, 0) : '—'}</td>

          <td class="boq-note"></td>

        </tr>`;

      });

    }

  });

  // ══════════════════════════════════════════════

  // CHI PHÍ KHÁC — section cấp dự án, cuối bảng

  // ══════════════════════════════════════════════

  const totalFloor = (project.rooms || []).reduce((s, r) => {

    const d = (+r.D||0)/1000, rv = (+r.R||0)/1000;

    return s + d * rv;

  }, 0);

  const OC_TEMPLATE = [

    { key: 'transport',   label: 'Phí vận chuyển',   unit: 'gói',   autoQty: false, defaultQty: 1 },

    { key: 'debris',      label: 'Phí tháo gỡ trần, vận chuyển + đổ xà bần, bao đựng rác',       unit: 'm²',       autoQty: true },

    { key: 'scaffold',    label: 'Phí thuê giàn giáo',                                             unit: 'm²',       autoQty: true },

    { key: 'design',      label: 'Phí thiết kế',                                                   unit: 'm²',       autoQty: true },

    { key: 'supervision', label: 'Phí giám sát ngoại tỉnh',                                        unit: 'lần',      autoQty: false, defaultQty: 1 },

  ];

  const oc = project.otherCosts || {};

  stt = 1;  // Reset STT cho CHI PHI KHAC

  html += `<tr class="boq-other-header"><td colspan="10">💰 CHI PHÍ KHÁC</td></tr>`;

  OC_TEMPLATE.forEach(tmpl => {

    const saved   = oc[tmpl.key] || {};

    const qty     = tmpl.autoQty

      ? +(totalFloor).toFixed(2)

      : +(saved.qty != null ? saved.qty : tmpl.defaultQty);

    const price   = +(saved.price || 0);

    const total   = qty * price;

    const noteVal = saved.note || '';

    html += `

      <tr class="boq-other-item">

        <td style="color:var(--text-muted);font-size:12px;text-align:center;">${stt++}</td>

        <td class="boq-other-label">${tmpl.label}

          ${tmpl.autoQty ? '<span class="oc-auto-tag">tự động theo sàn</span>' : ''}

        </td>

        <td class="boq-dim"></td><td class="boq-dim"></td><td class="boq-dim"></td>

        <td style="color:var(--text-secondary);text-align:center;">${tmpl.unit}</td>

        <td class="boq-qty">

          ${tmpl.autoQty

            ? `<span title="= tổng sàn dự án">${fmt(qty,2)}</span>`

            : `<input class="oc-input oc-qty" type="number" min="0" step="0.01"

                 value="${qty}"

                 onchange="updateOtherCost('${tmpl.key}','qty',this.value)"

                 title="Số lượng"/>`

          }

        </td>

        <td class="boq-price">

          <input class="oc-input oc-price" type="number" min="0"

            value="${price || ''}"

            placeholder="Nhập đơn giá"

            onchange="updateOtherCost('${tmpl.key}','price',this.value)"

            title="Đơn giá (₫)"/>

        </td>

        <td class="boq-total oc-total" id="oc-total-${tmpl.key}">

          ${total ? fmt(total, 0) : ''}

        </td>

        <td class="boq-note">

          <input class="oc-input oc-note" type="text"

            value="${noteVal}"

            placeholder="Ghi chú"

            onchange="updateOtherCost('${tmpl.key}','note',this.value)"

            style="width:100%;font-size:11px;"/>

        </td>

      </tr>`;

  });

  // ── Tổng tiền hạng mục (dựa trên items đã tính) ──────

  const grandSubtotal = (project.rooms || []).reduce((s, room) => {

    const calc = CALC.room(room);

    const roomTotal = calc.items.reduce((rs, it) => rs + (+it.total || 0), 0);

    // Cộng chi phí khác per-room nếu có

    return s + roomTotal;

  }, 0);

  // Cộng chi phí khác cấp dự án

  const ocVat = project.otherCosts || {};

  const totalFloorVat = (project.rooms||[]).reduce((s,r)=>s+(+r.D||0)/1000*(+r.R||0)/1000,0);

  const ocSubtotal = [

    { key:'transport',   autoQty:false, defaultQty:1 },

    { key:'debris',      autoQty:true },

    { key:'scaffold',    autoQty:true },

    { key:'design',      autoQty:true },

    { key:'supervision', autoQty:false, defaultQty:1 },

  ].reduce((s, tmpl) => {

    const saved = ocVat[tmpl.key] || {};

    const qty   = tmpl.autoQty ? totalFloorVat : +(saved.qty != null ? saved.qty : tmpl.defaultQty || 0);

    const price = +(saved.price || 0);

    return s + qty * price;

  }, 0);

  const totalBeforeVat = grandSubtotal + ocSubtotal;

  const vatRate = +(project.vatRate ?? 8) / 100;

  const vatAmt  = Math.round(totalBeforeVat * vatRate);

  const grandTotal = totalBeforeVat + vatAmt;

  const colSpanLeft = 7; // STT + Hạng mục + Dài + Rộng + Cao + ĐV + SL

  html += `

    <tr class="boq-total-row boq-subtotal-row" id="boq-row-subtotal">

      <td colspan="${colSpanLeft}" style="text-align:right;font-weight:700;padding:10px 12px;border-top:2px solid var(--border-color);color:var(--text-secondary);">

        Thành tiền (trước VAT):

      </td>

      <td style="text-align:right;font-weight:700;padding:10px 12px;border-top:2px solid var(--border-color);color:var(--brand-gold);" colspan="3">

        ${fmt(totalBeforeVat, 0)} đ

      </td>

    </tr>

    <tr class="boq-total-row boq-vat-row" id="boq-row-vat">

      <td colspan="${colSpanLeft}" style="text-align:right;padding:6px 12px;color:var(--text-secondary);">

        VAT (<span id="boq-vat-label">${Math.round(vatRate*100)}%</span>):

      </td>

      <td style="text-align:right;padding:6px 12px;color:var(--text-secondary);" colspan="3">

        ${fmt(vatAmt, 0)} đ

      </td>

    </tr>

    <tr class="boq-total-row boq-grandtotal-row" id="boq-row-grandtotal">

      <td colspan="8" style="text-align:center;font-weight:800;padding:10px 12px;font-size:14px;border-top:2px solid var(--brand-gold);color:var(--text-main);">

        TỔNG CỘNG

      </td>

      <td style="text-align:right;font-weight:800;padding:10px 12px;font-size:14px;border-top:2px solid var(--brand-gold);color:var(--brand-gold);" colspan="2">

        ${fmt(grandTotal, 0)} đ

      </td>

    </tr>

        <tr class="boq-total-row boq-words-row" id="boq-row-words">

      <td colspan="10" style="padding:8px 12px;font-style:italic;color:var(--text-secondary);font-size:12px;border-top:1px dashed var(--border-color);">

        Bằng chữ: <strong style="color:var(--text-main);">${numberToWords(grandTotal)}</strong>

      </td>

    </tr>

    <tr class="boq-notes-row" style="border:none !important;">

      <td colspan="10" style="border:none !important;padding:12px 12px 4px 12px;font-style:italic;text-align:left;color:var(--text-secondary);">

        Báo giá trên có giá trị trong vòng 30 ngày<br>

        _ Báo giá trên không bao gồm:<br>

        _ Thời gian thi công:

      </td>

    </tr>

    <tr class="boq-signature-row" style="border:none !important;">

      <td style="border:none !important;width:70px;"></td>

      <td colspan="4" style="border:none !important;padding:24px 12px 12px 12px;font-weight:bold;text-align:left;vertical-align:top;color:var(--text-main);">

        Xác nhận của khách hàng

      </td>

      <td colspan="5" style="border:none !important;padding:24px 12px 12px 12px;text-align:center;vertical-align:top;font-style:italic;color:var(--text-secondary);">

        TP. HCM ngày ...... tháng ...... năm 2026

      </td>

    </tr>

    <tr class="boq-signature-row" style="border:none !important;">

      <td style="border:none !important;"></td>

      <td colspan="4" style="border:none !important;"></td>

      <td colspan="5" style="border:none !important;padding:0 12px;text-align:center;font-weight:bold;color:var(--text-main);">

        Giám đốc

      </td>

    </tr>

    <tr class="boq-signature-row" style="border:none !important;height:60px;">

      <td colspan="10" style="border:none !important;height:60px;"></td>

    </tr>

    <tr class="boq-signature-row" style="border:none !important;">

      <td style="border:none !important;"></td>

      <td colspan="4" style="border:none !important;"></td>

      <td colspan="5" style="border:none !important;padding:0 12px;text-align:center;font-weight:bold;color:var(--text-main);">

        VŨ THỊ KIM CHÚC

      </td>

    </tr>`;

  tbody.innerHTML = html;

  // Apply filter

  if (filterSelect) {

    filterBOQByRoom(filterSelect.value);

  }

}

function filterBOQByRoom(roomId) {

  const summarySection = document.getElementById('boq-summary-section');

  const detailSection  = document.getElementById('boq-detail-section');

  const sectionLabel   = document.getElementById('boq-section-label');

  if (roomId === 'all') {

    // File tổng: hiện Tổng Hợp, ẩn Chi Tiết

    if (summarySection) summarySection.style.display = '';

    if (detailSection)  detailSection.style.display  = 'none';

    if (sectionLabel)   sectionLabel.innerHTML = '📊 1. BẢNG TỔNG HỢP KHỐI LƯỢNG TOÀN DỰ ÁN';

    // Ẩn per-room OC, hiện project-level OC

    document.querySelectorAll('#boq-tbody tr.boq-room-oc-hdr, #boq-tbody tr.boq-room-oc-item')

      .forEach(r => r.style.display = 'none');

    document.querySelectorAll('#boq-tbody tr.boq-other-header, #boq-tbody tr.boq-other-item')

      .forEach(r => r.style.display = '');

  } else {

    // Phòng cụ thể: ẩn Tổng Hợp, hiện Chi Tiết

    if (summarySection) summarySection.style.display = 'none';

    if (detailSection)  detailSection.style.display  = '';

    if (sectionLabel) {

      const project = DB.get(state.currentProjectId);

      const room = (project?.rooms || []).find(r => r.id === roomId);

      const roomName = room ? room.name.toUpperCase() : '';

      sectionLabel.innerHTML = `📋 2. BẢNG CHI TIẾT — ${roomName}`;

    }

    // Lọc các dòng dữ liệu phòng

    document.querySelectorAll('#boq-tbody tr').forEach(row => {

      const kr = row.dataset.kr;

      // Ẩn project-level OC khi xem từng phòng cụ thể (rows này không có data-kr)

      if (row.classList.contains('boq-other-header') || row.classList.contains('boq-other-item')) {

        row.style.display = 'none';

        return;

      }

      if (!kr) return; // rows không có data-kr (không nên có)

      if (row.classList.contains('boq-other-header') || row.classList.contains('boq-other-item')) {

        // Ẩn project-level OC khi xem từng phòng

        row.style.display = 'none';

      } else if (row.classList.contains('boq-room-oc-hdr') || row.classList.contains('boq-room-oc-item')) {

        // Hiện per-room OC của phòng đang chọn

        row.style.display = (kr === roomId) ? '' : 'none';

      } else {

        // Các dòng dữ liệu thông thường

        row.style.display = (kr === roomId) ? '' : 'none';

      }

    });

  }

}

// =============================================

// HẠNG MỤC THỦ CÔNG — INLINE EDITING

// =============================================

// Tạo dòng nhập liệu inline

function _buildInlineRow(roomId, itemId, insertIdx, prefill = {}) {

  const tr = document.createElement('tr');

  tr.className = 'ci-edit-row';

  tr.dataset.eRoom = roomId;

  tr.dataset.eItem = itemId || '';

  tr.dataset.eIdx  = insertIdx ?? '';

  tr.innerHTML = `

    <td style="text-align:center;color:#a78bfa;font-size:14px;">&#9998;</td>

    <td colspan="2" style="padding:4px 6px;position:relative;">

      <input class="ci-il" data-f="label" tabindex="1"

        value="${(prefill.label||'').replace(/"/g,'&quot;')}"

        placeholder="T&#234;n h&#7841;ng m&#7909;c *" style="width:100%;" />

      <div class="ci-vattu-suggest" style="display:none;position:absolute;top:100%;left:0;right:0;background:var(--bg-card);border:1px solid var(--brand-gold);border-radius:6px;z-index:9999;max-height:160px;overflow-y:auto;font-size:12px;box-shadow:0 4px 16px rgba(0,0,0,0.4);"></div>

    </td>

    <td style="padding:4px 4px;">

      <input class="ci-il" data-f="unit" tabindex="2"

        value="${prefill.unit||''}" placeholder="&#272;VT"

        style="width:56px;text-align:center;" />

    </td>

    <td style="padding:4px 4px;">

      <input class="ci-il" data-f="qty" type="number" step="0.01" tabindex="3"

        value="${prefill.qty||''}" placeholder="SL"

        style="width:65px;text-align:right;" />

    </td>

    <td style="padding:4px 4px;">

      <input class="ci-il" data-f="price" type="number" tabindex="4"

        value="${prefill.price||''}" placeholder="&#272;&#417;n gi&#225;"

        style="width:100px;text-align:right;" />

    </td>

    <td></td>

    <td style="padding:4px 6px;white-space:nowrap;">

      <input class="ci-il" data-f="note" tabindex="5"

        value="${prefill.note||''}" placeholder="Ghi ch&#250;" style="width:90px;" />

    </td>

    <td style="padding:4px 6px;white-space:nowrap;">

      <button class="btn-ci-isave" onclick="saveInlineRow(false)" title="L&#432;u (Shift+Enter)">&#10003; L&#432;u</button>

      <button class="btn-ci-icancel" onclick="cancelInlineRow()" title="H&#7911;y (Esc)">&#215;</button>

      <div style="font-size:10px;color:var(--text-muted);margin-top:2px;">Enter=L&#432;u+M&#7899;i &nbsp; Shift+Enter=L&#432;u</div>

    </td>`;

  // === FEATURE #6: Gợi ý giá từ Thư Viện Vật Tư ===

  const labelInput = tr.querySelector('.ci-il[data-f="label"]');

  const suggestBox = tr.querySelector('.ci-vattu-suggest');

  const unitInput  = tr.querySelector('.ci-il[data-f="unit"]');

  const priceInput = tr.querySelector('.ci-il[data-f="price"]');

  labelInput.addEventListener('input', () => {

    const q = labelInput.value.trim().toLowerCase();

    if (q.length < 2) { suggestBox.style.display = 'none'; return; }

    const all = VatTuDB.get();

    const matches = all.filter(v =>

      v.name.toLowerCase().includes(q) || (v.code||'').toLowerCase().includes(q)

    ).slice(0, 8);

    if (matches.length === 0) { suggestBox.style.display = 'none'; return; }

    suggestBox.innerHTML = matches.map((v, i) => `

      <div class="ci-vattu-item" data-idx="${i}"

        style="padding:6px 10px;cursor:pointer;border-bottom:1px solid rgba(255,255,255,0.06);

               display:flex;justify-content:space-between;align-items:center;"

        onmousedown="event.preventDefault()"

        onclick="_applyVatTuSuggest(this, '${v.name.replace(/'/g,"\\'")}',${'"'+v.unit+'"'},${'"'+v.price+'"'},${'"'+v.supplier+'"'})">

        <span style="font-weight:500;">${v.name}</span>

        <span style="color:var(--brand-gold);font-size:11px;">${v.price ? v.price.toLocaleString('vi-VN')+' đ/'+v.unit : v.unit}</span>

      </div>`).join('');

    suggestBox.style.display = 'block';

  });

  labelInput.addEventListener('blur', () => {

    setTimeout(() => { suggestBox.style.display = 'none'; }, 200);

  });

  // Excel-like keyboard navigation

  tr.addEventListener('keydown', e => {

    if (e.key === 'Escape') { cancelInlineRow(); return; }

    if (e.key === 'Enter' && e.target.tagName !== 'BUTTON') {

      e.preventDefault();

      if (e.shiftKey) {

        saveInlineRow(false);   // Shift+Enter: luu roi thoi

      } else {

        saveInlineRow(true);    // Enter: luu va mo dong moi

      }

      return;

    }

    // Tab tu o cuoi (note) -> tu dong sang o label cua dong moi

    if (e.key === 'Tab' && !e.shiftKey && e.target.dataset.f === 'note') {

      e.preventDefault();

      saveInlineRow(true);

    }

  });

  return tr;

}

// Callback áp dụng gợi ý vật tư vào các ô trong dòng inline

function _applyVatTuSuggest(el, name, unit, price, supplier) {

  const tr = el.closest('tr.ci-edit-row');

  if (!tr) return;

  const labelIn = tr.querySelector('.ci-il[data-f="label"]');

  const unitIn  = tr.querySelector('.ci-il[data-f="unit"]');

  const priceIn = tr.querySelector('.ci-il[data-f="price"]');

  const noteIn  = tr.querySelector('.ci-il[data-f="note"]');

  if (labelIn) labelIn.value = name;

  if (unitIn  && unit)  unitIn.value  = unit;

  if (priceIn && price) priceIn.value = price;

  if (noteIn  && supplier) noteIn.value = supplier;

  // Ẩn suggest box

  const sb = tr.querySelector('.ci-vattu-suggest');

  if (sb) sb.style.display = 'none';

  priceIn?.focus();

}

// Chèn dòng mới tại vị trí insertIdx (null = cuối)

function startInsertRow(roomId, insertIdx) {

  cancelInlineRow();

  let anchor;

  if (insertIdx === null) {

    anchor = document.querySelector(`tr.boq-add-row[data-kr=""]`);

    if (!anchor) anchor = document.querySelector(`tr.boq-add-row`); // fallback

  } else {

    anchor = document.querySelector(`tr.ci-insert-bar[data-ri="${roomId}"][data-ii="${insertIdx}"]`);

  }

  if (!anchor) return;

  const tr = _buildInlineRow(roomId, '', insertIdx);

  anchor.insertAdjacentElement('beforebegin', tr);

  tr.querySelector('.ci-il[data-f="label"]')?.focus();

}

// Sửa dòng hiện có

function startEditRow(roomId, itemId) {

  cancelInlineRow();

  const project = DB.get(state.currentProjectId);

  const room = (project?.rooms||[]).find(r => r.id === roomId);

  const ci = (room?.customItems||[]).find(c => c.id === itemId);

  if (!ci) return;

  const origRow = document.querySelector(`tr[data-ci="${itemId}"]`);

  if (!origRow) return;

  const tr = _buildInlineRow(roomId, itemId, null, ci);

  origRow.replaceWith(tr);

  tr.querySelector('.ci-il[data-f="label"]')?.focus();

}

// Lưu dòng inline

function saveInlineRow(autoNext = false) {

  const tr = document.querySelector('tr.ci-edit-row');

  if (!tr) return;

  const roomId    = tr.dataset.eRoom;

  const itemId    = tr.dataset.eItem;

  const insertIdx = tr.dataset.eIdx !== '' ? +tr.dataset.eIdx : null;

  const get = f => tr.querySelector(`.ci-il[data-f="${f}"]`)?.value?.trim() || '';

  const label = get('label');

  if (!label) {

    tr.querySelector('.ci-il[data-f="label"]').style.borderColor = '#ef4444';

    tr.querySelector('.ci-il[data-f="label"]').focus();

    return;

  }

  const unit  = get('unit');

  const qty   = parseFloat(get('qty'))   || 0;

  const price = parseFloat(get('price')) || 0;

  const note  = get('note');

  const project = DB.get(state.currentProjectId);

  const room = (project?.rooms||[]).find(r => r.id === roomId);

  if (!room) return;

  let ci = [...(room.customItems||[])];

  if (itemId) {

    const i = ci.findIndex(c => c.id === itemId);

    if (i !== -1) ci[i] = { ...ci[i], label, unit, qty, price, note };

  } else if (insertIdx != null) {

    ci.splice(insertIdx, 0, { id: genId(), label, unit, qty, price, note });

  } else {

    ci.push({ id: genId(), label, unit, qty, price, note });

  }

  DB.updateRoom(state.currentProjectId, roomId, { customItems: ci });

  if (autoNext) {

    // Luu va mo ngay dong nhap moi (Excel-like)

    refreshWorkspace();

    // Mo dong nhap moi o cuoi (sau khi re-render)

    setTimeout(() => startInsertRow(roomId, null), 50);

  } else {

    refreshWorkspace();

  }

}

function cancelInlineRow() {

  const tr = document.querySelector('tr.ci-edit-row');

  if (tr) {

    // Nếu đang edit (có itemId) thì refresh để hiện lại dòng gốc

    if (tr.dataset.eItem) refreshWorkspace();

    else tr.remove();

  }

}

// Giữ lại editCustomItem (legacy – gọi startEditRow)

function editCustomItem(roomId, itemId) { startEditRow(roomId, itemId); }

// openAddItemDialog legacy – gọi startInsertRow

function openAddItemDialog(roomId, editId, insertIdx) {

  if (editId) startEditRow(roomId, editId);

  else startInsertRow(roomId, insertIdx ?? null);

}

function saveAddItem()   { saveInlineRow(); }

function closeAddItem()  { cancelInlineRow(); }

