function renderMaterialOptions() {

  // Helper: render single-select

  const render = (containerId, type, selectedId) => {

    const c = document.getElementById(containerId);

    if (!c) return;

    const matList = MATERIALS[type] || [];

    c.innerHTML = matList.map(m => {

      const pct = m.waste > 0 ? ` <span style="color:var(--brand-gold);font-size:10px;">+${(m.waste*100).toFixed(0)}%</span>` : '';

      return `<button class="mat-option${m.id === selectedId ? ' selected' : ''}" data-id="${m.id}" data-type="${type}" data-container="${containerId}">${m.label}${pct}</button>`;

    }).join('');

    // "Khác" input

    if (containerId === 'mat-wall-z1' || containerId === 'mat-wall-z2' || containerId === 'mat-wall') {

      const otherId = `${containerId}-other-label`;

      const otherVal = state.selMat[containerId.replace('mat-','').replace('-','').replace('z','Z')] === 'other'

        ? (state.selMat.otherLabel?.[containerId] || '') : '';

      c.insertAdjacentHTML('beforeend',

        `<input id="${otherId}" class="other-mat-input" type="text" placeholder="Nhập tên vật liệu…"

          value="${otherVal}" style="display:${selectedId==='other'?'inline-block':'none'};

          margin-top:6px;width:100%;padding:5px 8px;background:var(--bg-input);border:1px solid var(--brand-gold);

          border-radius:4px;color:var(--text-main);font-size:12px;"

          oninput="state.selMat.otherLabel=state.selMat.otherLabel||{};state.selMat.otherLabel['${containerId}']=this.value;updatePreview();"/>`);

    }

    c.querySelectorAll('.mat-option').forEach(btn => {

      btn.addEventListener('click', () => {

        c.querySelectorAll('.mat-option').forEach(b => b.classList.remove('selected'));

        btn.classList.add('selected');

        const cid = btn.dataset.container;

        if (cid === 'mat-wall-z1') state.selMat.wallZ1 = btn.dataset.id;

        else if (cid === 'mat-wall-z2') state.selMat.wallZ2 = btn.dataset.id;

        else state.selMat[btn.dataset.type] = btn.dataset.id;

        // Hiện/ẩn input "Khác"

        const oi = document.getElementById(`${cid}-other-label`);

        if (oi) oi.style.display = (btn.dataset.id === 'other') ? 'inline-block' : 'none';

        updatePreview();

      });

    });

  };

  // Helper: render multi-select cho ceiling

  const renderMulti = (containerId, type, selectedIds) => {

    const c = document.getElementById(containerId);

    if (!c) return;

    const sel = Array.isArray(selectedIds) ? selectedIds : (selectedIds ? [selectedIds] : []);

    const matList = MATERIALS[type] || [];

    c.innerHTML = matList.map(m => {

      const pct = m.waste > 0 ? ` <span style="color:var(--brand-gold);font-size:10px;">+${(m.waste*100).toFixed(0)}%</span>` : '';

      const isSelected = sel.includes(m.id);

      return `<button class="mat-option${isSelected ? ' selected' : ''}" data-id="${m.id}" data-type="${type}" data-container="${containerId}">${m.label}${pct}</button>`;

    }).join('');

    c.insertAdjacentHTML('afterbegin',

      `<span style="font-size:10px;color:var(--text-muted);margin-right:6px;align-self:center;">Chọn nhiều:</span>`);

    c.querySelectorAll('.mat-option').forEach(btn => {

      btn.addEventListener('click', () => {

        const id = btn.dataset.id;

        if (id === 'none') {

          // "Bỏ qua" xóa hết lựa chọn khác

          c.querySelectorAll('.mat-option').forEach(b => b.classList.remove('selected'));

          btn.classList.add('selected');

          state.selMat.ceilMats = [];

        } else {

          // Bỏ chọn "Bỏ qua" nếu đang chọn

          c.querySelectorAll('.mat-option[data-id="none"]').forEach(b => b.classList.remove('selected'));

          btn.classList.toggle('selected');

          const now = Array.from(c.querySelectorAll('.mat-option.selected')).map(b => b.dataset.id).filter(x => x !== 'none');

          state.selMat.ceilMats = now;

          if (now.length === 0) {

            c.querySelectorAll('.mat-option[data-id="none"]').forEach(b => b.classList.add('selected'));

          }

        }

        updatePreview();

      });

    });

  };

  render('mat-floor',    'floor',   state.selMat.floor);

  render('mat-wall',     'wall',    state.selMat.wall);

  render('mat-wall-z1',  'wall',    state.selMat.wallZ1);

  render('mat-wall-z2',  'wallZ2',  state.selMat.wallZ2);  // Vùng 2: không có gạch

  renderMulti('mat-ceiling', 'ceiling', state.selMat.ceilMats);

}

function updatePreview() {

  const D  = (+document.getElementById('room-D').value  || 0) / 1000;

  const R  = (+document.getElementById('room-R').value  || 0) / 1000;

  const H  = (+document.getElementById('room-H').value  || 0) / 1000;

  const nd = +document.getElementById('room-doors').value    || 0;

  const dw = (+document.getElementById('room-door-w').value  || 900)  / 1000;

  const dh = (+document.getElementById('room-door-h').value  || 2100) / 1000;

  const nw = +document.getElementById('room-windows').value  || 0;

  const ww = (+document.getElementById('room-window-w').value || 1200) / 1000;

  const wh = (+document.getElementById('room-window-h').value || 1200) / 1000;

  const da = dw * dh;

  const wa = ww * wh;

  const perim = 2 * (D + R);

  const fMat = getMat('floor',   state.selMat.floor);

  const wMat = getMat('wall',    state.selMat.wall);

  const ceilId0 = (state.selMat.ceilMats || [])[0] || 'none';

  const cMat = getMat('ceiling', ceilId0);

  const floor = D * R * (1 + fMat.waste);

  const wall  = Math.max(0, (perim * H - nd*da - nw*wa) * (1 + wMat.waste));

  const ceil  = D * R * (1 + cMat.waste);

  const pgEl = document.getElementById('preview-grid');

  if (!pgEl) return; // Section đã bị ẩn/xóa — bỏ qua

  pgEl.innerHTML = `

    <div class="preview-item">

      <span class="preview-val">${D && R ? fmt(floor) : '—'}</span>

      <span class="preview-lbl">m² sàn</span>

    </div>

    <div class="preview-item">

      <span class="preview-val">${D && R && H ? fmt(wall) : '—'}</span>

      <span class="preview-lbl">m² tường</span>

    </div>

    <div class="preview-item">

      <span class="preview-val">${D && R ? fmt(ceil) : '—'}</span>

      <span class="preview-lbl">m² trần</span>

    </div>

    <div class="preview-item" style="border-top:1px dashed var(--border);padding-top:8px;margin-top:4px;">

      <span class="preview-val" style="color:var(--brand-blue-light);">${D && R ? perim.toFixed(2).replace('.',',') : '—'}</span>

      <span class="preview-lbl">m chu vi</span>

    </div>`;

}

// Cập nhật hiển thị chiều cao Vùng 2 (tự động = H - Z1H)

function updateZ2HDisplay() {

  const H   = +document.getElementById('room-H').value || 0;

  const z1h = +document.getElementById('wall-z1-h').value || 0;

  const z2h = Math.max(0, H - z1h);

  const el  = document.getElementById('wall-z2-h-display');

  if (el) el.textContent = z2h > 0 ? `${z2h.toLocaleString('vi-VN')} mm` : '— mm';

}

// Tự điền chiều cao Vùng 1 khi nhập H phòng

// Mặc định: Vùng 1 = H (toàn bộ chiều cao), người dùng ghi đè thủ công

function autoFillZ1Height(hVal) {

  const H = +hVal || 0;

  const z1Input = document.getElementById('wall-z1-h');

  if (!z1Input) return;

  // Chỉ tự fill nếu người dùng chưa nhập hoặc đang để giá trị mặc định

  const currentZ1 = +z1Input.value || 0;

  const prevH = +z1Input.dataset.prevH || 0;

  if (currentZ1 === 0 || currentZ1 === prevH) {

    z1Input.value = H > 0 ? H : '';

  }

  z1Input.dataset.prevH = H;

  updateZ2HDisplay();

  updatePreview();

}

