let currentWizardStep = 1;

function goToWizardStep(step) {
  if (step < 1 || step > 3) return;
  currentWizardStep = step;

  // 1. Hide all step contents, show the active one
  for (let i = 1; i <= 3; i++) {
    const el = document.getElementById(`step-content-${i}`);
    if (el) {
      el.style.display = i === step ? 'block' : 'none';
    }
  }

  // 2. Update stepper step active classes
  for (let i = 1; i <= 3; i++) {
    const el = document.getElementById(`step-node-${i}`);
    if (el) {
      if (i < step) {
        el.className = 'stepper-step completed';
      } else if (i === step) {
        el.className = 'stepper-step active';
      } else {
        el.className = 'stepper-step';
      }
    }
  }

  // 3. Update stepper progress bar width
  const progress = document.getElementById('wizard-progress');
  if (progress) {
    progress.style.width = `${(step - 1) * 50}%`;
  }

  // 4. Update step title text
  const stepTitle = document.getElementById('wizard-step-title');
  if (stepTitle) {
    if (step === 1) stepTitle.textContent = 'Bước 1/3 — Kích thước phòng';
    else if (step === 2) stepTitle.textContent = 'Bước 2/3 — Chọn vật liệu';
    else if (step === 3) stepTitle.textContent = 'Bước 3/3 — Đính kèm ảnh hiện trạng';
  }

  // 5. Update footer buttons
  const btnPrev = document.getElementById('btn-wizard-prev');
  const btnNext = document.getElementById('btn-wizard-next');

  if (btnPrev) {
    btnPrev.style.display = step === 1 ? 'none' : 'block';
  }

  if (btnNext) {
    if (step === 3) {
      const isEdit = !!state.editingRoomId;
      btnNext.textContent = isEdit ? 'Lưu Thay Đổi' : 'Thêm Phòng';
    } else {
      btnNext.textContent = 'Tiếp theo';
    }
  }
}

function nextWizardStep() {
  if (currentWizardStep === 1) {
    const name = document.getElementById('room-name').value.trim();
    if (!name) {
      document.getElementById('room-name').focus();
      document.getElementById('room-name').style.borderColor = 'var(--brand-red)';
      return;
    }
    document.getElementById('room-name').style.borderColor = '';

    const D = parseFloat(document.getElementById('room-D').value);
    const R = parseFloat(document.getElementById('room-R').value);
    if (!D || !R) {
      showToast('Vui lòng nhập kích thước Dài (D) và Rộng (R)!', 'warning');
      if (!D) document.getElementById('room-D').focus();
      else document.getElementById('room-R').focus();
      return;
    }
  }

  if (currentWizardStep < 3) {
    goToWizardStep(currentWizardStep + 1);
  } else {
    saveRoom();
  }
}

function prevWizardStep() {
  if (currentWizardStep > 1) {
    goToWizardStep(currentWizardStep - 1);
  }
}

function openRoomModal(room = null) {

  state.editingRoomId = room?.id || null;

  const isEdit = !!room;

  const project = DB.get(state.currentProjectId);

  const projType = project?.type || 'residential';

  renderQuickRoomButtons(projType);

  const projSuffix = project ? ` — Dự án: ${project.name}` : '';

  const roomTitleEl = document.getElementById('modal-room-title');
  if (roomTitleEl) {
    roomTitleEl.textContent = (isEdit ? 'Sửa Phòng' : 'Thêm Phòng / Khu Vực') + projSuffix;
  }

  const saveLabelEl = document.getElementById('btn-save-room-label');
  if (saveLabelEl) {
    saveLabelEl.textContent = isEdit ? 'Lưu Thay Đổi' : 'Thêm Phòng';
  }

  const mobileLabel = document.getElementById('btn-save-room-label-mobile');

  if (mobileLabel) mobileLabel.textContent = isEdit ? 'Lưu Thay Đổi' : 'Thêm Phòng';

  goToWizardStep(1);

  document.getElementById('room-name').value                  = room?.name     || '';

  const roomFunc = room?.funcLabel || 'kho';
  document.getElementById('room-function').value = roomFunc;
  updateRoomDiagnostic(roomFunc);

  document.getElementById('room-D').value                     = room?.D        || '';

  document.getElementById('room-R').value                     = room?.R        || '';

  document.getElementById('room-H').value                     = room?.H        || '';

  document.getElementById('room-doors').value                 = room?.doors    ?? 1;

  document.getElementById('room-door-w').value                = room?.doorW    ?? 900;

  document.getElementById('room-door-h').value                = room?.doorH    ?? 2100;

  document.getElementById('room-windows').value               = room?.windows  ?? 1;

  document.getElementById('room-window-w').value              = room?.windowW  ?? 1200;

  document.getElementById('room-window-h').value              = room?.windowH  ?? 1200;

  const floorPriceEl = document.getElementById('room-floor-price');
  if (floorPriceEl) floorPriceEl.value = room?.floorPrice || '';

  const wallPriceEl = document.getElementById('room-wall-price');
  if (wallPriceEl) wallPriceEl.value = room?.wallPrice || '';

  const ceilPriceEl = document.getElementById('room-ceil-price');
  if (ceilPriceEl) ceilPriceEl.value = room?.ceilPrice || '';

  document.getElementById('room-note').value                  = room?.roomNote   || '';

  // Electrical inputs & backward compatibility migration
  let noteLights = room?.elecNoteLights || '';
  if (!noteLights && room) {
    const lightsParts = [];
    if (room.elecLightDl > 0) lightsParts.push(`đèn downlight ${room.elecLightDl} bộ`);
    if (room.elecLightSl > 0) lightsParts.push(`đèn spotlight ${room.elecLightSl} bộ`);
    if (room.elecLightPanel > 0) lightsParts.push(`đèn panel ${room.elecLightPanel} bộ`);
    if (room.elecLightTuyp1200 > 0) lightsParts.push(`đèn tuýp 1200mm ${room.elecLightTuyp1200} bộ`);
    if (room.elecLightTuyp600 > 0) lightsParts.push(`đèn tuýp 600mm ${room.elecLightTuyp600} bộ`);
    if (room.elecLightLed > 0) lightsParts.push(`đèn LED dây ${room.elecLightLed} m`);
    noteLights = lightsParts.join(', ');
  }
  if (document.getElementById('elec-note-lights'))
    document.getElementById('elec-note-lights').value = noteLights;

  let notePanel = room?.elecNotePanel || '';
  if (!notePanel && room) {
    const panelParts = [];
    if (room.elecSw2 > 0) panelParts.push(`mặt 2 công tắc ${room.elecSw2} mặt`);
    if (room.elecSw1 > 0) panelParts.push(`mặt 1 công tắc ${room.elecSw1} mặt`);
    if (room.elecOutlet > 0) panelParts.push(`ổ cắm đôi 2 cực ${room.elecOutlet} bộ`);
    if (room.elecCb1 > 0) panelParts.push(`CB 1 pha ${room.elecCb1} cái`);
    if (room.elecCb2 > 0) panelParts.push(`CB 2 pha ${room.elecCb2} cái`);
    if (room.elecCb3 > 0) panelParts.push(`CB 3 pha ${room.elecCb3} cái`);
    if (room.elecPanelBox > 0) panelParts.push(`tủ điện ${room.elecPanelBox} bộ`);
    if (room.elecFan > 0) panelParts.push(`quạt hút âm trần ${room.elecFan} cái`);
    notePanel = panelParts.join(', ');
  }
  if (document.getElementById('elec-note-panel'))
    document.getElementById('elec-note-panel').value = notePanel;

  let noteAc = room?.elecNoteAc || '';
  if (!noteAc && room) {
    const acParts = [];
    if (room.elecAcWall > 0) acParts.push(`máy lạnh treo tường ${room.elecAcWall} cái`);
    if (room.elecAcCeil > 0) acParts.push(`máy lạnh âm trần ${room.elecAcCeil} cái`);
    if (room.elecAcCentral > 0) acParts.push(`máy lạnh trung tâm ${room.elecAcCentral} cái`);
    noteAc = acParts.join(', ');
  }
  if (document.getElementById('elec-note-ac'))
    document.getElementById('elec-note-ac').value = noteAc;

  if (document.getElementById('elec-nep'))
    document.getElementById('elec-nep').value = room?.elecNep ?? 0;
  if (document.getElementById('elec-ong-ruot'))
    document.getElementById('elec-ong-ruot').value = room?.elecOngRuot ?? 0;
  if (document.getElementById('elec-ong-cung'))
    document.getElementById('elec-ong-cung').value = room?.elecOngCung ?? 0;

  if (document.getElementById('note-woodwork'))

    document.getElementById('note-woodwork').value  = room?.noteWoodwork  || '';

  if (document.getElementById('note-plumbing')) {
    const combinedNotes = [room?.notePlumbing, room?.noteWaterproof].filter(Boolean).join('\n');
    document.getElementById('note-plumbing').value = combinedNotes;
  }

  // Load ảnh hiện trạng phân loại
  state.roomCategorizedPhotos = {
    overview: [],
    den: [],
    tudien: [],
    maylanh: [],
    noithat: [],
    wc: [],
    other: []
  };

  if (room && room.photos) {
    if (Array.isArray(room.photos)) {
      state.roomCategorizedPhotos.overview = [...room.photos];
    } else {
      state.roomCategorizedPhotos.overview = room.photos.overview ? [...room.photos.overview] : [];
      state.roomCategorizedPhotos.den = room.photos.den ? [...room.photos.den] : [];
      state.roomCategorizedPhotos.tudien = room.photos.tudien ? [...room.photos.tudien] : [];
      state.roomCategorizedPhotos.maylanh = room.photos.maylanh ? [...room.photos.maylanh] : [];
      state.roomCategorizedPhotos.noithat = room.photos.noithat ? [...room.photos.noithat] : [];
      state.roomCategorizedPhotos.wc = room.photos.wc ? [...room.photos.wc] : [];
      state.roomCategorizedPhotos.other = room.photos.other ? [...room.photos.other] : [];
    }
  }

  renderCategorizedRoomPhotos('overview');
  renderCategorizedRoomPhotos('den');
  renderCategorizedRoomPhotos('tudien');
  renderCategorizedRoomPhotos('maylanh');
  renderCategorizedRoomPhotos('noithat');
  renderCategorizedRoomPhotos('wc');
  renderCategorizedRoomPhotos('other');

  // Zone mode

  const zoneOn = !!room?.wallZone;

  state.wallZoneMode = zoneOn;

  document.getElementById('wall-zone-toggle').checked = zoneOn;

  document.getElementById('wall-single-mode').style.display  = zoneOn ? 'none' : '';

  document.getElementById('wall-zone-mode').style.display    = zoneOn ? '' : 'none';

  document.getElementById('wall-z1-h').value                  = room?.wallZ1H   || 1800;

  document.getElementById('room-wall-price-z1').value         = room?.wallPriceZ1 || '';

  document.getElementById('room-wall-price-z2').value         = room?.wallPriceZ2 || '';

  document.getElementById('room-window-sill').value           = room?.wallSill   || 900;

  updateZ2HDisplay();

  state.selMat = {

    floor:     room?.floorMat   || 'none',

    wall:      room?.wallMat    || 'none',

    ceilMats:  Array.isArray(room?.ceilMats) ? room.ceilMats

               : (room?.ceilMat ? [room.ceilMat] : []),  // backward compat

    wallZ1:    room?.wallMatZ1  || 'none',

    wallZ2:    room?.wallMatZ2  || 'none',

    otherLabel: room?.wallOtherLabel || {},

  };

  renderMaterialOptions();

  updatePreview();

  document.getElementById('modal-room').classList.add('open');

  setTimeout(() => document.getElementById('room-name').focus(), 50);

  // Lưu trạng thái gốc của form phòng để dirty check

  state.originalRoomData = JSON.stringify(getRoomDataFromUI());

}

