async function exportPDFExcel() {

  const project = DB.get(state.currentProjectId);

  if (!project || !project.rooms || project.rooms.length === 0) {

    alert('Chưa có dữ liệu để xuất!');

    return;

  }

  // Generate sheets using the shared helper

  const wbData = generateWorkbook(project);

  if (!wbData) return;

  // Store globally so confirm function can access it

  window.currentWbData = wbData;

  // Build the checkbox list in the modal

  const listContainer = document.getElementById('pdf-sheets-list');

  if (!listContainer) {

    console.error('pdf-sheets-list container not found');

    return;

  }

  let html = '';

  // 1. Summary sheet

  html += `

    <label style="display: flex; align-items: center; gap: 8px; padding: 6px; cursor: pointer; border-bottom: 1px solid var(--border-faint, rgba(255,255,255,0.04));">

      <input type="checkbox" id="chk-pdf-summary" value="summary" checked style="width: 16px; height: 16px; cursor: pointer;">

      <span style="font-weight: bold; font-size: 13px; color: var(--text-primary);">Bảng tổng hợp</span>

    </label>

  `;

  // 2. Room sheets

  wbData.roomSheets.forEach((rs, idx) => {

    html += `

      <label style="display: flex; align-items: center; gap: 8px; padding: 6px; cursor: pointer; border-bottom: 1px solid var(--border-faint, rgba(255,255,255,0.04));">

        <input type="checkbox" class="chk-pdf-room" value="${idx}" checked style="width: 16px; height: 16px; cursor: pointer;">

        <span style="font-size: 13px; color: var(--text-primary);">Phòng: ${rs.room.name}</span>

      </label>

    `;

  });

  // 3. Materials sheet

  html += `

    <label style="display: flex; align-items: center; gap: 8px; padding: 6px; cursor: pointer;">

      <input type="checkbox" id="chk-pdf-materials" value="materials" style="width: 16px; height: 16px; cursor: pointer;">

      <span style="font-size: 13px; color: var(--text-primary);">Bảng vật tư cần mua</span>

    </label>

  `;

  listContainer.innerHTML = html;

  // Open the modal overlay

  document.getElementById('modal-export-pdf-options').classList.add('open');

  if (window.lucide) {

    window.lucide.createIcons();

  }

}

function closeExportPdfModal() {

  document.getElementById('modal-export-pdf-options').classList.remove('open');

}

function toggleSelectAllPdfSheets(selected) {

  const checkboxes = document.querySelectorAll('#pdf-sheets-list input[type="checkbox"]');

  checkboxes.forEach(cb => cb.checked = selected);

}

function confirmExportPDFExcel() {

  const wbData = window.currentWbData;

  if (!wbData) {

    alert('Không tìm thấy dữ liệu xuất!');

    return;

  }

  const chkSummary = document.getElementById('chk-pdf-summary')?.checked;

  const chkMaterials = document.getElementById('chk-pdf-materials')?.checked;

  const roomCheckboxes = document.querySelectorAll('.chk-pdf-room');

  const selectedRoomIndexes = [];

  roomCheckboxes.forEach(cb => {

    if (cb.checked) {

      selectedRoomIndexes.push(parseInt(cb.value, 10));

    }

  });

  if (!chkSummary && !chkMaterials && selectedRoomIndexes.length === 0) {

    alert('Vui lòng chọn ít nhất một sheet để xuất PDF!');

    return;

  }

  const selectedSheets = [];

  if (chkSummary) {

    selectedSheets.push({ ws: wbData.wsSum });

  }

  selectedRoomIndexes.forEach(idx => {

    const rs = wbData.roomSheets[idx];

    if (rs) {

      selectedSheets.push({ ws: rs.ws });

    }

  });

  if (chkMaterials) {

    selectedSheets.push({ ws: wbData.wsVT });

  }

  const totalPages = selectedSheets.length;

  let finalHtml = '';

  selectedSheets.forEach((sheetObj, pageIndex) => {

    const wsHtml = renderWorksheetToHtml(sheetObj.ws);

    finalHtml += `

      <div class="ep-page">

        ${wsHtml}

        <div class="ep-footer">

          <span>Du-Toan-BlueAI Lab</span>

          <span>Trang ${pageIndex + 1}/${totalPages}</span>

        </div>

      </div>

    `;

  });

  // Inject into container, close modal, and print

  const container = document.getElementById('excel-pdf-content');

  if (!container) {

    alert('Không tìm thấy container excel-pdf-content!');

    return;

  }

  container.innerHTML = finalHtml;

  closeExportPdfModal();

  if (new URLSearchParams(window.location.search).get('mock_print') === 'true') {
    const el = document.getElementById("excel-pdf-content");
    el.style.display = "block";
    el.style.position = "fixed";
    el.style.top = "0";
    el.style.left = "0";
    el.style.width = "100%";
    el.style.height = "100%";
    el.style.backgroundColor = "white";
    el.style.zIndex = "999999";
    el.style.overflow = "auto";
    return;
  }

  document.body.classList.add('print-excel-pdf');

  window.print();

  document.body.classList.remove('print-excel-pdf');

  // Increment export count in localStorage
  const currentCount = parseInt(localStorage.getItem('bkl_export_count') || '0');
  try {
    localStorage.setItem('bkl_export_count', (currentCount + 1).toString());
  } catch (e) {}
  if (typeof updateDashboardStats === 'function') updateDashboardStats();

  container.innerHTML = '';

}

function renderWorksheetToHtml(ws) {

  if (!ws || !ws['!ref']) return '';

  const range = XLSX.utils.decode_range(ws['!ref']);

  const merges = ws['!merges'] || [];

  // Build a map of merged cells

  const mergeMap = {};

  merges.forEach(m => {

    for (let r = m.s.r; r <= m.e.r; r++) {

      for (let c = m.s.c; c <= m.e.c; c++) {

        const isStart = (r === m.s.r && c === m.s.c);

        mergeMap[`${r},${c}`] = { m, isStart };

      }

    }

  });

  // Calculate col widths

  let colHtml = '';

  if (ws['!cols']) {

    colHtml += '<colgroup>';

    for (let c = range.s.c; c <= range.e.c; c++) {

      const col = ws['!cols'][c];

      const w = col && col.wch ? col.wch * 8 : 80;

      colHtml += `<col style="width:${w}px;">`;

    }

    colHtml += '</colgroup>';

  }

  let rowsHtml = '';

  let titleRowsHtml = '';

  let headerRowsHtml = '';

  let dataRowsHtml = '';

  const headerStart = 8;

  const headerEnd = ws.isDetail ? 9 : 8;

  for (let r = range.s.r; r <= range.e.r; r++) {

    let rowHtml = '';

    // Check if row is empty

    let isRowEmpty = true;

    for (let c = range.s.c; c <= range.e.c; c++) {

      const cellRef = XLSX.utils.encode_cell({ r, c });

      if (ws[cellRef] && ws[cellRef].v !== undefined && ws[cellRef].v !== '') {

        isRowEmpty = false;

        break;

      }

    }

    rowHtml += '<tr>';

    for (let c = range.s.c; c <= range.e.c; c++) {

      const offset = 0;

      // 1. Logo cell gộp ở A1:B3

      if (r === 0 && c === 0) {

        rowHtml += `<td rowspan="3" colspan="2" style="vertical-align: middle; text-align: left; padding: 4px 6px; border: none;"><img src="logo-bluedecor.png" style="height: 96px; object-fit: contain;" onerror="this.style.display='none'"></td>`;

        continue;

      }

      if (r < 3 && c < 2) {

        // Bỏ qua vì đã gộp vào logo

        continue;

      }

      const mergeInfo = mergeMap[`${r},${c}`];

      if (mergeInfo && !mergeInfo.isStart) {

        continue; // Covered by merge

      }

      const cellRef = XLSX.utils.encode_cell({ r, c });

      const cell = ws[cellRef] || { t: 's', v: '' };

      let cellStyles = '';

      if (cell.s) {

        // Font

        if (cell.s.font) {

          const font = cell.s.font;

          if (font.name) cellStyles += `font-family:'${font.name}', 'Times New Roman', serif;`;

          if (font.sz) cellStyles += `font-size:${font.sz}pt;`;

          if (font.bold) cellStyles += `font-weight:bold;`;

          if (font.italic) cellStyles += `font-style:italic;`;

          if (font.color && font.color.rgb) cellStyles += `color:#${font.color.rgb};`;

        }

        // Fill

        if (cell.s.fill && cell.s.fill.fgColor && cell.s.fill.fgColor.rgb) {

          cellStyles += `background-color:#${cell.s.fill.fgColor.rgb};`;

        }

        // Alignment

        if (cell.s.alignment) {

          const align = cell.s.alignment;

          if (align.horizontal) cellStyles += `text-align:${align.horizontal};`;

          if (align.vertical) cellStyles += `vertical-align:${align.vertical};`;

          if (align.wrapText) cellStyles += `white-space:normal;word-break:break-word;`;

          else cellStyles += `white-space:nowrap;`;

          if (align.indent) {

            cellStyles += `padding-left:${align.indent * 15}px !important;`;

          }

        }

        // Borders

        if (cell.s.border) {

          const border = cell.s.border;

          const getBorderStyle = (b) => {

            if (!b || b.style === 'none') return 'none';

            const w = b.style === 'medium' ? '1.5pt' : '0.5pt';

            const t = b.style === 'dashed' ? 'dashed' : 'solid';

            const c = b.color && b.color.rgb ? `#${b.color.rgb}` : '#000000';

            return `${w} ${t} ${c}`;

          };

          const tS = getBorderStyle(border.top);

          const bS = getBorderStyle(border.bottom);

          const lS = getBorderStyle(border.left);

          const rS = getBorderStyle(border.right);

          if (tS === 'none' && bS === 'none' && lS === 'none' && rS === 'none') {

            cellStyles += 'border:none;';

          } else {

            if (border.top) cellStyles += `border-top:${tS};`;

            if (border.bottom) cellStyles += `border-bottom:${bS};`;

            if (border.left) cellStyles += `border-left:${lS};`;

            if (border.right) cellStyles += `border-right:${rS};`;

          }

        }

      }

      // Default padding

      cellStyles += `padding: 4px 6px; box-sizing: border-box;`;

      let colspanAttr = '';

      let rowspanAttr = '';

      if (mergeInfo && mergeInfo.isStart) {

        const m = mergeInfo.m;

        const colspan = m.e.c - m.s.c + 1;

        const rowspan = m.e.r - m.s.r + 1;

        if (colspan > 1) colspanAttr = ` colspan="${colspan}"`;

        if (rowspan > 1) rowspanAttr = ` rowspan="${rowspan}"`;

      }

      let valToShow = cell.v !== undefined ? cell.v : '';

      if (cell.w !== undefined) valToShow = cell.w;

      if (typeof valToShow === 'string') {

        valToShow = valToShow

          .replace(/&/g, '&amp;')

          .replace(/</g, '&lt;')

          .replace(/>/g, '&gt;')

          .replace(/\n/g, '<br>');

      }

      rowHtml += `<td style="${cellStyles}"${colspanAttr}${rowspanAttr}>${valToShow}</td>`;

    }

    rowHtml += '</tr>';

    rowsHtml += rowHtml;

    if (r < headerStart) {

      titleRowsHtml += rowHtml;

    } else if (r >= headerStart && r <= headerEnd) {

      headerRowsHtml += rowHtml;

    } else {

      dataRowsHtml += rowHtml;

    }

  }

  const tableClass = ws.isDetail ? 'class="ep-detail-table"' : '';

  if (range.e.r < headerStart) {

    return `

      <table ${tableClass} style="border-collapse: collapse; width: 100%; font-family: 'Times New Roman', Times, serif; margin: 0 auto; page-break-inside: auto; table-layout: fixed;">

        ${colHtml}

        <tbody>

          ${rowsHtml}

        </tbody>

      </table>

    `;

  }

  return `

    <table ${tableClass} style="border-collapse: collapse; width: 100%; font-family: 'Times New Roman', Times, serif; margin: 0 auto; page-break-inside: auto; table-layout: fixed; margin-bottom: 0; border-bottom: none;">

      ${colHtml}

      <tbody>

        ${titleRowsHtml}

      </tbody>

    </table>

    <table ${tableClass} style="border-collapse: collapse; width: 100%; font-family: 'Times New Roman', Times, serif; margin: 0 auto; page-break-inside: auto; table-layout: fixed; margin-top: 0; border-top: none;">

      ${colHtml}

      <thead>

        ${headerRowsHtml}

      </thead>

      <tbody>

        ${dataRowsHtml}

      </tbody>

    </table>

  `;

}

