// 21. TỰ ĐỘNG ĐỒNG BỘ EXCEL & PDF

// =============================================

async function triggerAutoSync() {
  try {
    const project = DB.get(state.currentProjectId);
    if (!project || !project.rooms || project.rooms.length === 0) return;

    const wbData = generateWorkbook(project);
    if (!wbData) return;

    const out = XLSX.write(wbData.wb, { bookType: 'xlsx', bookSST: false, type: 'binary' });
    const buf = s2ab(out);

    if (typeof JSZip === 'undefined') {
      console.warn('JSZip not found, cannot auto-sync.');
      return;
    }

    const logoBuf = logoArrayBuffer || null;
    const zip = await JSZip.loadAsync(buf);

    const sheetFiles = Object.keys(zip.files).filter(name => name.startsWith("xl/worksheets/sheet") && name.endsWith(".xml"));

    for (const file of sheetFiles) {
      let xmlStr = await zip.file(file).async("string");

      if (xmlStr.includes("<pageMargins") && !xmlStr.includes("<headerFooter")) {
        const pageSetupXml = '<pageSetup paperSize="9" orientation="landscape" fitToWidth="1" fitToHeight="0" fitToPage="1"/>';
        const footerText = '&amp;L&amp;&quot;Arial,Italic&quot;Du-Toan-BlueAI Lab&amp;R&amp;&quot;Arial,Bold&quot;Trang &amp;P/&amp;N';
        const headerFooterXml = `<headerFooter oddFooter="${footerText}" evenFooter="${footerText}"/>`;
        xmlStr = xmlStr.replace(/(<pageMargins[^>]*\/>)/, `$1${pageSetupXml}${headerFooterXml}`);
      }

      if (logoBuf && !xmlStr.includes("<drawing")) {
        xmlStr = xmlStr.replace("</worksheet>", '<drawing r:id="rId2"/></worksheet>');
        const match = file.match(/sheet(\d+)\.xml/);
        if (match) {
          const sheetNum = match[1];
          const relsFile = `xl/worksheets/_rels/sheet${sheetNum}.xml.rels`;
          const sheetRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">\n<Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" Target="../drawings/drawing1.xml"/>\n</Relationships>`;
          zip.file(relsFile, sheetRelsXml);
        }
      }

      zip.file(file, xmlStr);
    }

    if (logoBuf) {
      const drawingXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<xdr:wsDr xmlns:xdr="http://schemas.openxmlformats.org/drawingml/2006/spreadsheetDrawing" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main">\n<xdr:twoCellAnchor editAs="oneCell">\n<xdr:from>\n<xdr:col>1</xdr:col>\n<xdr:colOff>500000</xdr:colOff>\n<xdr:row>0</xdr:row>\n<xdr:rowOff>63501</xdr:rowOff>\n</xdr:from>\n<xdr:to>\n<xdr:col>1</xdr:col>\n<xdr:colOff>1976156</xdr:colOff>\n<xdr:row>3</xdr:row>\n<xdr:rowOff>100000</xdr:rowOff>\n</xdr:to>\n<xdr:pic>\n<xdr:nvPicPr>\n<xdr:cNvPr id="2" name="Picture 3"/>\n<xdr:cNvPicPr>\n<a:picLocks noChangeAspect="1" noChangeArrowheads="1"/>\n</xdr:picLocks>\n</xdr:picPr>\n<xdr:blipFill>\n<a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="rId1" cstate="print"/>\n<a:srcRect/>\n<a:stretch>\n<a:fillRect/>\n</a:stretch>\n</xdr:blipFill>\n<xdr:spPr bwMode="auto">\n<a:xfrm>\n<a:off x="698500" y="63501"/>\n<a:ext cx="1476156" cy="844549"/>\n</a:xfrm>\n<a:prstGeom prst="rect">\n<a:avLst/>\n</a:prstGeom>
<a:noFill/>\n<a:ln>\n<a:noFill/>\n</a:ln>\n</xdr:spPr>\n</xdr:pic>\n<xdr:clientData/>\n</xdr:twoCellAnchor>\n</xdr:wsDr>`;
      const drawingRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">\n<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/image1.png"/>\n</Relationships>`;
      
      zip.file("xl/drawings/drawing1.xml", drawingXml);
      zip.file("xl/drawings/_rels/drawing1.xml.rels", drawingRelsXml);
      zip.file("xl/media/image1.png", logoBuf);

      let contentTypes = await zip.file("[Content_Types].xml").async("string");
      if (!contentTypes.includes("/xl/drawings/drawing1.xml")) {
        contentTypes = contentTypes.replace("</Types>", '<Override PartName="/xl/drawings/drawing1.xml" ContentType="application/vnd.openxmlformats-officedocument.drawing+xml"/></Types>');
        zip.file("[Content_Types].xml", contentTypes);
      }
    }

    const zipBase64 = await zip.generateAsync({ type: "base64" });

    let folder = 'du-toan';
    const pathParts = window.location.pathname.split('/');
    for (let part of pathParts) {
      if (part.includes('du-toan') || part.includes('khoi-luong-pro')) {
        folder = decodeURIComponent(part);
        break;
      }
    }

    const response = await fetch('/api/sync-project-files', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        folder: folder,
        project_name: project.name,
        excel_base64: zipBase64
      })
    });
    
    const result = await response.json();
    console.log('Auto-sync status:', result);
  } catch (err) {
    console.error('Auto-sync error:', err);
  }
}


// =============================================
// 22. QUẢN LÝ ẢNH HIỆN TRẠNG TỪNG PHÒNG
// =============================================

function getRoomPhotosCount(room) {
  if (!room || !room.photos) return 0;
  if (Array.isArray(room.photos)) return room.photos.length;
  let count = 0;
  ['overview', 'den', 'tudien', 'maylanh'].forEach(cat => {
    if (Array.isArray(room.photos[cat])) {
      count += room.photos[cat].length;
    }
  });
  return count;
}

function getRoomPhotos(room, category) {
  if (!room || !room.photos) return [];
  if (Array.isArray(room.photos)) {
    return category === 'overview' ? room.photos : [];
  }
  return room.photos[category] || [];
}

window.viewPhotoData = function(data) {
  const w = window.open();
  w.document.write(`<img src="${data}" style="max-width:100%;height:auto;">`);
};

async function renderCategorizedRoomPhotos(category) {
  const thumbs = document.getElementById(`room-photo-thumbs-${category}`);
  if (!thumbs) return;
  
  if (state.categoryObjectUrls && state.categoryObjectUrls[category]) {
    state.categoryObjectUrls[category].forEach(url => URL.revokeObjectURL(url));
  }
  if (!state.categoryObjectUrls) state.categoryObjectUrls = {};
  state.categoryObjectUrls[category] = [];

  const photos = (state.roomCategorizedPhotos && state.roomCategorizedPhotos[category]) || [];
  thumbs.innerHTML = ''; 

  for (let i = 0; i < photos.length; i++) {
    const p = photos[i];
    
    const wrapper = document.createElement('div');
    wrapper.className = 'room-photo-thumb';
    wrapper.title = p.name;

    const img = document.createElement('img');
    img.alt = p.name;
    
    let imageUrl = '';
    if (p.data && (p.data.startsWith('data:') || p.data.startsWith('blob:'))) {
      imageUrl = p.data;
    } else if (p.id) {
      try {
        const blob = await PhotoDB.getPhoto(p.id);
        if (blob) {
          imageUrl = URL.createObjectURL(blob);
          state.categoryObjectUrls[category].push(imageUrl);
          p.data = imageUrl; // Cache URL in memory
        } else {
          imageUrl = 'placeholder.png';
        }
      } catch (err) {
        console.error('Failed to get photo:', p.id, err);
        imageUrl = 'placeholder.png';
      }
    } else {
      imageUrl = 'placeholder.png';
    }

    img.src = imageUrl;
    img.onclick = () => window.viewPhotoData(imageUrl);

    const delBtn = document.createElement('span');
    delBtn.className = 'thumb-del';
    delBtn.title = 'Xóa ảnh';
    delBtn.textContent = '✕';
    delBtn.onclick = (e) => {
      e.stopPropagation();
      removeCategorizedRoomPhoto(category, i);
    };

    wrapper.appendChild(img);
    wrapper.appendChild(delBtn);
    thumbs.appendChild(wrapper);
  }
}

function removeCategorizedRoomPhoto(category, idx) {
  if (!state.roomCategorizedPhotos || !state.roomCategorizedPhotos[category]) return;
  state.roomCategorizedPhotos[category].splice(idx, 1);
  renderCategorizedRoomPhotos(category);
}

async function handleRoomPhotoSelect(files, category) {
  if (!files || files.length === 0) return;
  if (!state.roomCategorizedPhotos) {
    state.roomCategorizedPhotos = {
      overview: [], den: [], tudien: [], maylanh: [], noithat: [], wc: [], other: []
    };
  }
  if (!state.roomCategorizedPhotos[category]) {
    state.roomCategorizedPhotos[category] = [];
  }

  const promises = Array.from(files).map(async file => {
    const isImage = file.type.startsWith('image/') ||
                    file.type === '' ||
                    /\.(heic|heif|jpg|jpeg|png|webp|gif)$/i.test(file.name);
    if (!isImage) return;

    try {
      const compressed = await compressImage(file, 1280, 0.7);
      const blob = dataURLtoBlob(compressed.data);
      if (blob) {
        const photoId = genId();
        await PhotoDB.savePhoto(photoId, blob);
        state.roomCategorizedPhotos[category].push({
          id: photoId,
          name: file.name,
          date: new Date().toISOString(),
          data: URL.createObjectURL(blob)
        });
      }
    } catch (e) {
      console.warn('Compress failed:', file.name, e);
      showToast('Không thể xử lý ảnh: ' + file.name, 'error');
    }
  });

  await Promise.all(promises);
  renderCategorizedRoomPhotos(category);
  
  const inputEl = document.getElementById('room-photo-input-' + category);
  if (inputEl) {
    inputEl.value = '';
  }
}

function saveDataToStorage() {
  if (state.currentProjectId) {
    const project = DB.get(state.currentProjectId);
    if (project) {
      const projects = DB.load();
      const idx = projects.findIndex(p => p.id === project.id);
      if (idx !== -1) {
        projects[idx] = project;
      }
      DB.save(projects);
    }
  }
}

function updateUIWorkspace() {
  refreshWorkspace();
}

async function handleRoomCardPhotoSelect(event, roomId) {
  const files = event.target.files;
  if (!files || files.length === 0) return;

  const project = DB.get(state.currentProjectId);
  if (!project) return;

  const room = (project.rooms || []).find(r => r.id === roomId);
  if (!room) return;

  if (!room.photos) room.photos = { overview: [], den: [], tudien: [], maylanh: [], noithat: [], wc: [], other: [] };
  if (Array.isArray(room.photos)) {
    room.photos = { overview: [...room.photos], den: [], tudien: [], maylanh: [], noithat: [], wc: [], other: [] };
  }
  if (!room.photos.overview) {
    room.photos.overview = [];
  }

  const promises = Array.from(files).map(file => {
    if (!file.type.startsWith('image/')) return Promise.resolve();
    
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = e => {
        const img = new Image();
        img.onload = () => {
          let w = img.width;
          let h = img.height;
          const maxW = 600;
          if (w > maxW) {
            h = Math.round(h * maxW / w);
            w = maxW;
          }
          const canvas = document.createElement('canvas');
          canvas.width = w;
          canvas.height = h;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(img, 0, 0, w, h);
          resolve({
            name: file.name,
            data: canvas.toDataURL('image/jpeg', 0.6)
          });
        };
        img.onerror = () => resolve(null);
        img.src = e.target.result;
      };
      reader.onerror = () => resolve(null);
      reader.readAsDataURL(file);
    });
  });

  const compressedResults = await Promise.all(promises);
  compressedResults.forEach(res => {
    if (res) {
      room.photos.overview.push(res);
    }
  });

  DB.updateRoom(state.currentProjectId, roomId, { photos: room.photos });
  saveDataToStorage();
  updateUIWorkspace();
}


function docDepBoNho() {
  let totalBefore = 0;
  for (let k in localStorage) {
    if (localStorage.hasOwnProperty(k)) totalBefore += localStorage[k].length * 2;
  }

  const keysToKeep = ['bkl_v1_projects', 'bkl_settings', 'bkl_vattu'];
  for (let k in localStorage) {
    if (localStorage.hasOwnProperty(k) && !keysToKeep.includes(k)) {
      localStorage.removeItem(k);
    }
  }

  let totalAfter = 0;
  for (let k in localStorage) {
    if (localStorage.hasOwnProperty(k)) totalAfter += localStorage[k].length * 2;
  }

  const freed = ((totalBefore - totalAfter) / 1024).toFixed(0);
  showToast(`Đã giải phóng ${freed} KB bộ nhớ`, 'success');
}

function showToast(message, type = 'info', duration = 3500) {
  let container = document.getElementById('toast-container');
  if (!container) {
    container = document.createElement('div');
    container.id = 'toast-container';
    document.body.appendChild(container);
  }

  const toast = document.createElement('div');
  toast.className = `toast toast-${type}`;
  
  let iconHtml = '';
  if (type === 'success') {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>`;
  } else if (type === 'warning') {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>`;
  } else if (type === 'error' || type === 'danger') {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>`;
  } else {
    iconHtml = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>`;
  }

  toast.innerHTML = `
    <span class="toast-icon" style="display: flex; align-items: center; justify-content: center;">${iconHtml}</span>
    <span class="toast-message" style="flex-grow: 1; margin-right: 8px;">${message}</span>
    <button class="toast-close" style="background: none; border: none; color: inherit; opacity: 0.6; cursor: pointer; padding: 4px; display: flex; align-items: center; justify-content: center;" aria-label="Đóng">
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
    </button>
  `;

  const close = () => {
    toast.classList.remove('visible');
    toast.addEventListener('transitionend', () => toast.remove(), { once: true });
  };

  toast.querySelector('.toast-close').addEventListener('click', close);
  container.appendChild(toast);

  requestAnimationFrame(() => {
    toast.classList.add('visible');
  });

  if (duration > 0) {
    setTimeout(close, duration);
  }
}

// =============================================
// PHOTO INDEXEDDB UTILITIES
// =============================================

const PhotoDB = {
  DB_NAME: 'BocKhoiLuongPhotosDB',
  DB_VERSION: 1,
  STORE_NAME: 'photos',
  db: null,

  open() {
    return new Promise((resolve, reject) => {
      if (this.db) return resolve(this.db);
      const request = indexedDB.open(this.DB_NAME, this.DB_VERSION);
      
      request.onerror = (e) => reject(request.error);
      request.onsuccess = (e) => {
        this.db = request.result;
        resolve(this.db);
      };
      
      request.onupgradeneeded = (e) => {
        const db = request.result;
        if (!db.objectStoreNames.contains(this.STORE_NAME)) {
          db.createObjectStore(this.STORE_NAME);
        }
      };
    });
  },

  async getPhoto(id) {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(this.STORE_NAME, 'readonly');
      const store = transaction.objectStore(this.STORE_NAME);
      const request = store.get(id);
      
      request.onerror = () => reject(request.error);
      request.onsuccess = () => resolve(request.result || null);
    });
  },

  async savePhoto(id, blob) {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(this.STORE_NAME, 'readwrite');
      const store = transaction.objectStore(this.STORE_NAME);
      const request = store.put(blob, id);
      
      request.onerror = () => reject(request.error);
      request.onsuccess = () => resolve();
    });
  },

  async deletePhoto(id) {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(this.STORE_NAME, 'readwrite');
      const store = transaction.objectStore(this.STORE_NAME);
      const request = store.delete(id);
      
      request.onerror = () => reject(request.error);
      request.onsuccess = () => resolve();
    });
  }
};

function dataURLtoBlob(dataurl) {
  try {
    const arr = dataurl.split(',');
    const mime = arr[0].match(/:(.*?);/)[1];
    const bstr = atob(arr[1]);
    let n = bstr.length;
    const u8arr = new Uint8Array(n);
    while (n--) {
      u8arr[n] = bstr.charCodeAt(n);
    }
    return new Blob([u8arr], { type: mime });
  } catch (e) {
    console.error('Failed to convert dataurl to blob', e);
    return null;
  }
}

function blobToBase64(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(reader.error);
    reader.onload = () => {
      const dataUrl = reader.result;
      const base64 = dataUrl.split(',')[1];
      resolve(base64);
    };
    reader.readAsDataURL(blob);
  });
}

async function migratePhotosToIndexedDB() {
  const projects = DB.load();
  let migratedCount = 0;
  let hasChanges = false;

  for (const proj of projects) {
    // 1. Migrate project site photos
    if (proj.sitePhotos && Array.isArray(proj.sitePhotos)) {
      for (let i = 0; i < proj.sitePhotos.length; i++) {
        const p = proj.sitePhotos[i];
        if (p.data && p.data.startsWith('data:')) {
          const blob = dataURLtoBlob(p.data);
          if (blob) {
            const id = genId();
            await PhotoDB.savePhoto(id, blob);
            proj.sitePhotos[i] = { id, name: p.name, date: p.date || new Date().toISOString() };
            migratedCount++;
            hasChanges = true;
          }
        }
      }
    }

    // 2. Migrate room photos
    if (!proj.rooms) continue;
    for (const room of proj.rooms) {
      if (!room.photos) continue;
      
      if (Array.isArray(room.photos)) {
        const legacyPhotos = room.photos;
        room.photos = {
          overview: [], den: [], tudien: [], maylanh: [], noithat: [], wc: [], other: []
        };
        for (const p of legacyPhotos) {
          if (p.data && p.data.startsWith('data:')) {
            const blob = dataURLtoBlob(p.data);
            if (blob) {
              const id = genId();
              await PhotoDB.savePhoto(id, blob);
              room.photos.overview.push({ id, name: p.name, date: p.date || new Date().toISOString() });
              migratedCount++;
              hasChanges = true;
            }
          }
        }
      } else {
        const categories = ['overview', 'den', 'tudien', 'maylanh', 'noithat', 'wc', 'other'];
        for (const cat of categories) {
          const list = room.photos[cat];
          if (!list || !Array.isArray(list)) continue;
          
          for (let i = 0; i < list.length; i++) {
            const p = list[i];
            if (p.data && p.data.startsWith('data:')) {
              const blob = dataURLtoBlob(p.data);
              if (blob) {
                const id = genId();
                await PhotoDB.savePhoto(id, blob);
                list[i] = { id, name: p.name, date: p.date || new Date().toISOString() };
                migratedCount++;
                hasChanges = true;
              }
            }
          }
        }
      }
    }
  }

  if (hasChanges) {
    try {
      localStorage.setItem(DB.KEY, JSON.stringify(projects));
      console.log(`[MIGRATION] Đã chuyển đổi ${migratedCount} ảnh cũ sang IndexedDB thành công.`);
    } catch (e) {
      console.error('[MIGRATION] Lưu database lỗi:', e);
    }
  }
}

async function isBlobHEIC(blob) {
  if (blob.type === 'image/heic' || blob.type === 'image/heif') return true;
  try {
    const buffer = await blob.slice(0, 16).arrayBuffer();
    const arr = new Uint8Array(buffer);
    if (arr.length < 12) return false;
    const ftyp = String.fromCharCode(...arr.slice(4, 12));
    return ftyp === 'ftypheic' || ftyp === 'ftypheix' || ftyp === 'ftypmif1' || ftyp === 'ftypmsf1';
  } catch (e) {
    return false;
  }
}

